    /// **ADR-202 β-1 (2026-06-17)** — `Mesh::sphere_great_circle_arc` extracts
    /// the host face's Sphere surface and returns a great-circle Arc on it; a
    /// non-Sphere face returns None.
    #[test]
    fn adr202_mesh_sphere_great_circle_arc() {
        use crate::curves::{AnalyticCurve, CurveOps};
        let mut mesh = Mesh::new();
        let r = 5.0;
        let faces = mesh.create_sphere_kernel_native(DVec3::ZERO, r, MaterialId::new(0)).unwrap();
        let sphere_face = faces[0];
        let a = DVec3::new(5.0, 0.0, 0.0);
        let b = DVec3::new(0.0, 0.0, 5.0);
        let arc = mesh.sphere_great_circle_arc(sphere_face, a, b).expect("arc on sphere face");
        let (sa, ea) = match arc {
            AnalyticCurve::Arc { start_angle, end_angle, radius, center, .. } => {
                assert!((radius - r).abs() < 1e-9, "arc radius = sphere radius");
                assert!((center - DVec3::ZERO).length() < 1e-9, "arc center = sphere center");
                (start_angle, end_angle)
            }
            _ => panic!("expected Arc"),
        };
        let dummy = Mesh::new();
        assert!((arc.evaluate(sa, &dummy).unwrap() - a).length() < 1e-9, "endpoint A");
        assert!((arc.evaluate(ea, &dummy).unwrap() - b).length() < 1e-9, "endpoint B");
        for k in 0..=12 {
            let t = sa + (ea - sa) * (k as f64 / 12.0);
            let p = arc.evaluate(t, &dummy).unwrap();
            assert!((p.length() - r).abs() < 1e-8, "sample on sphere");
        }

        // A polygon (no surface) face → None.
        let mut plane_mesh = Mesh::new();
        let v0 = plane_mesh.add_vertex(DVec3::new(0.0, 0.0, 0.0));
        let v1 = plane_mesh.add_vertex(DVec3::new(10.0, 0.0, 0.0));
        let v2 = plane_mesh.add_vertex(DVec3::new(10.0, 10.0, 0.0));
        let v3 = plane_mesh.add_vertex(DVec3::new(0.0, 10.0, 0.0));
        let pf = plane_mesh.add_face(&[v0, v1, v2, v3], MaterialId::new(0)).unwrap();
        assert!(plane_mesh.sphere_great_circle_arc(pf, a, b).is_none(), "non-sphere face → None");
    }

    /// **ADR-202 β-2b (2026-06-17)** — split a sphere hemisphere face by a closed
    /// circle on the sphere → cap + annulus, both inheriting the Sphere surface,
    /// manifold valid. Sphere (2 hemispheres) + 1 circle in the north → 3 faces.
    #[test]
    fn adr202_split_sphere_face_by_circle() {
        use crate::curves::AnalyticCurve;
        use crate::surfaces::{sphere::circle_on_sphere, AnalyticSurface};
        let mut mesh = Mesh::new();
        let c = DVec3::ZERO;
        let r = 5.0;
        let faces = mesh.create_sphere_kernel_native(c, r, MaterialId::new(0)).unwrap();
        assert_eq!(faces.len(), 2, "sphere = 2 hemispheres");
        // north hemisphere = the +Z (v∈[0,π/2]) face.
        let north = faces.iter().copied().find(|&f| {
            matches!(mesh.faces[f].surface(),
                Some(AnalyticSurface::Sphere { v_range, .. }) if v_range.1 > 0.0)
        }).expect("north face");

        // Circle in the north hemisphere (center at north pole, latitude band).
        let circle = circle_on_sphere(c, r, DVec3::new(0.0, 0.0, 5.0), DVec3::new(3.0, 0.0, 4.0)).unwrap();
        // sanity: circle at z=4, radius 3 (entirely in north hemisphere).
        if let AnalyticCurve::Circle { center, radius, .. } = &circle {
            assert!((center.z - 4.0).abs() < 1e-9 && (radius - 3.0).abs() < 1e-9);
        }

        let (cap, annulus) = mesh.split_sphere_face_by_circle(north, circle).expect("split");
        assert_eq!(annulus, north, "host face becomes the annulus");
        assert_ne!(cap, annulus);

        // 3 active faces total (cap + annulus + south).
        let active = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        assert_eq!(active, 3, "cap + annulus + south = 3 faces, got {}", active);

        // both cap & annulus carry a Sphere surface (ADR-089 A-χ inheritance).
        assert!(matches!(mesh.faces[cap].surface(), Some(AnalyticSurface::Sphere { .. })), "cap = Sphere");
        assert!(matches!(mesh.faces[annulus].surface(), Some(AnalyticSurface::Sphere { .. })), "annulus = Sphere");
        // annulus gained an inner hole (the circle).
        assert_eq!(mesh.faces[annulus].inners().len(), 1, "annulus has 1 inner hole (the circle)");

        // manifold valid.
        let inv = mesh.verify_face_invariants();
        assert!(inv.is_valid(), "manifold valid after sphere split: {:?}",
            inv.violations.iter().take(3).collect::<Vec<_>>());

        // non-Sphere face / non-Circle curve → None.
        let mut pm = Mesh::new();
        let v0 = pm.add_vertex(DVec3::ZERO);
        let v1 = pm.add_vertex(DVec3::new(10.0, 0.0, 0.0));
        let v2 = pm.add_vertex(DVec3::new(10.0, 10.0, 0.0));
        let v3 = pm.add_vertex(DVec3::new(0.0, 10.0, 0.0));
        let pf = pm.add_face(&[v0, v1, v2, v3], MaterialId::new(0)).unwrap();
        let dummy_circle = AnalyticCurve::Circle { center: DVec3::ZERO, radius: 1.0, normal: DVec3::Z, basis_u: DVec3::X };
        assert!(pm.split_sphere_face_by_circle(pf, dummy_circle).is_none(), "non-sphere host → None");
    }

    /// **ADR-202 β-3b smooth boundary (2026-06-17)** — `tessellate_sphere_clipped`
    /// splits straddling triangles AT the circle, so the cap/annulus boundary
    /// follows the smooth circle (boundary verts exactly on it), every vertex
    /// stays on the sphere, and the two faces sit on opposite sides of the
    /// circle plane (no z-fight). A plain hemisphere returns None.
    #[test]
    fn adr202_tessellate_sphere_clipped_smooth_boundary() {
        use crate::surfaces::{sphere::circle_on_sphere, AnalyticSurface};
        let mut mesh = Mesh::new();
        let c = DVec3::ZERO;
        let r = 5.0;
        let faces = mesh.create_sphere_kernel_native(c, r, MaterialId::new(0)).unwrap();
        let north = faces.iter().copied().find(|&f| matches!(mesh.faces[f].surface(),
            Some(AnalyticSurface::Sphere { v_range, .. }) if v_range.1 > 0.0)).unwrap();
        let south = faces.iter().copied().find(|&f| f != north).unwrap();
        let chord = 0.1;

        // plain hemisphere → None (no clip, full tessellation unchanged).
        assert!(mesh.tessellate_sphere_clipped(north, chord).is_none(), "plain hemisphere → None");
        assert!(mesh.tessellate_sphere_clipped(south, chord).is_none(), "plain hemisphere → None");

        // circle at z=4, radius 3 (center (0,0,4), normal +Z), in the north hemisphere.
        let circle = circle_on_sphere(c, r, DVec3::new(0.0, 0.0, 5.0), DVec3::new(3.0, 0.0, 4.0)).unwrap();
        let (cap, annulus) = mesh.split_sphere_face_by_circle(north, circle).unwrap();

        let cap_t = mesh.tessellate_sphere_clipped(cap, chord).expect("cap clipped");
        let ann_t = mesh.tessellate_sphere_clipped(annulus, chord).expect("annulus clipped");
        assert!(!cap_t.triangles.is_empty() && !ann_t.triangles.is_empty(), "both non-empty");

        // every vertex stays on the sphere (boundary verts included).
        for v in cap_t.vertices.iter().chain(ann_t.vertices.iter()) {
            assert!(((*v - c).length() - r).abs() < 1e-5, "vertex on sphere: {:?}", v);
        }
        // SMOOTH BOUNDARY — the split introduces boundary verts EXACTLY on the
        // circle (z≈4, x²+y²≈9), not jagged triangle steps.
        let on_circle = |v: &&DVec3| (v.z - 4.0).abs() < 1e-5
            && ((v.x * v.x + v.y * v.y).sqrt() - 3.0).abs() < 1e-5;
        let cap_b = cap_t.vertices.iter().filter(on_circle).count();
        let ann_b = ann_t.vertices.iter().filter(on_circle).count();
        assert!(cap_b >= 3, "cap boundary follows the circle ({} on-circle verts)", cap_b);
        assert!(ann_b >= 3, "annulus inner boundary follows the circle ({})", ann_b);
        // cap = toward-pole side (z ≥ 4); annulus = below the circle (z ≤ 4) → no overlap.
        for v in &cap_t.vertices {
            assert!(v.z >= 4.0 - 1e-4, "cap is the toward-pole region (z={})", v.z);
        }
        for v in &ann_t.vertices {
            assert!(v.z <= 4.0 + 1e-4, "annulus is below the circle (z={})", v.z);
        }
    }

    /// **ADR-202 (2026-06-17)** — drawing 2+ circles on ONE hemisphere makes the
    /// host face carry multiple circle holes (clips.len() > 1). The render clip
    /// must stay SMOOTH at EVERY circle (Sutherland-Hodgman against each in turn,
    /// not the old jagged per-triangle centroid fallback). Verifies the host's
    /// boundary lands on BOTH circles and every vertex stays on the sphere.
    #[test]
    fn adr202_tessellate_sphere_clipped_multi_circle_smooth() {
        use crate::curves::AnalyticCurve;
        use crate::surfaces::{sphere::circle_on_sphere, AnalyticSurface};
        let mut mesh = Mesh::new();
        let c = DVec3::ZERO;
        let r = 5.0;
        let chord = 0.1;
        let faces = mesh.create_sphere_kernel_native(c, r, MaterialId::new(0)).unwrap();
        let north = faces.iter().copied().find(|&f| matches!(mesh.faces[f].surface(),
            Some(AnalyticSurface::Sphere { v_range, .. }) if v_range.1 > 0.0)).unwrap();

        // two separated small circles on the north hemisphere (+Y and -Y sides).
        let circle1 = circle_on_sphere(c, r, DVec3::new(0.0, 2.5, 4.0), DVec3::new(0.0, 4.0, 3.0)).unwrap();
        let circle2 = circle_on_sphere(c, r, DVec3::new(0.0, -2.5, 4.0), DVec3::new(0.0, -4.0, 3.0)).unwrap();
        let circ = |a: &AnalyticCurve| match a {
            AnalyticCurve::Circle { center, radius, normal, .. } => (*center, *radius, normal.normalize()),
            _ => unreachable!(),
        };
        let (cc1, cr1, n1) = circ(&circle1);
        let (cc2, cr2, n2) = circ(&circle2);

        // carve both out of the SAME hemisphere → host ends with 2 inner holes.
        let (_cap1, host) = mesh.split_sphere_face_by_circle(north, circle1).unwrap();
        let (_cap2, host2) = mesh.split_sphere_face_by_circle(host, circle2).unwrap();
        assert_eq!(host, host2, "second split carves the same host face");
        assert_eq!(mesh.faces[host2].inners().len(), 2, "host carries 2 circle holes");

        let t = mesh.tessellate_sphere_clipped(host2, chord).expect("multi-hole host clipped");
        assert!(!t.triangles.is_empty(), "host renders");

        // every vertex on the sphere.
        for v in &t.vertices {
            assert!(((*v - c).length() - r).abs() < 1e-5, "vertex on sphere: {:?}", v);
        }
        // boundary verts land exactly on circle1 OR circle2 (smooth, not jagged
        // centroid steps): in the circle plane AND at the circle radius.
        let on = |v: DVec3, cc: DVec3, cr: f64, n: DVec3| {
            let rel = v - cc;
            rel.dot(n).abs() < 1e-4 && ((rel - n * rel.dot(n)).length() - cr).abs() < 1e-4
        };
        let b1 = t.vertices.iter().filter(|&&v| on(v, cc1, cr1, n1)).count();
        let b2 = t.vertices.iter().filter(|&&v| on(v, cc2, cr2, n2)).count();
        assert!(b1 >= 3, "host boundary follows circle1 smoothly ({b1} on-circle verts)");
        assert!(b2 >= 3, "host boundary follows circle2 smoothly ({b2})");
    }

    /// **ADR-093 (2026-06-17)** — a Path B sphere's two hemisphere faces are one
    /// logical sphere: they must share a single `surface_owner_id` so a single
    /// click on either selects the whole sphere (SelectTool walks owner siblings),
    /// not just one half. Also the equator edge is a SOFT smooth seam.
    #[test]
    fn adr093_sphere_hemispheres_share_surface_owner() {
        let mut mesh = Mesh::new();
        let faces = mesh
            .create_sphere_kernel_native(DVec3::ZERO, 5.0, MaterialId::new(0))
            .unwrap();
        assert_eq!(faces.len(), 2, "Path B sphere = 2 hemispheres");
        let o0 = mesh.face_surface_owner_id(faces[0]);
        let o1 = mesh.face_surface_owner_id(faces[1]);
        assert!(o0.is_some(), "north hemisphere has a surface_owner_id");
        assert_eq!(o0, o1, "both hemispheres share ONE surface_owner_id");
        // a click on either hemisphere walks to the whole sphere.
        let sibs = mesh.walk_face_owner_siblings(faces[0]);
        assert_eq!(sibs.len(), 2, "owner walk selects both hemispheres (whole sphere)");
        // the equator self-loop edge is SOFT (smooth seam, hidden in wireframe).
        let eid = mesh.faces[faces[0]].outer().start;
        assert!(
            mesh.hes[eid].flags().contains(HeFlags::SOFT),
            "equator half-edge is SOFT (smooth seam)"
        );
    }

    /// **ADR-186 (2026-06-17)** — drawing a coplanar feature at a sphere's equator
    /// (z=0) must NOT destroy the sphere. The coplanar re-derive must protect
    /// curved-surface faces + their boundary edges (the equator self-loop, whose
    /// anchor sits on z=0). Without the guard, the equator was polygonised +
    /// removed and the two hemispheres collapsed into flat polygons.
    #[test]
    fn adr186_coplanar_rederive_protects_sphere_equator() {
        let mut mesh = Mesh::new();
        let faces = mesh
            .create_sphere_kernel_native(DVec3::ZERO, 5.0, MaterialId::new(0))
            .unwrap();
        assert_eq!(faces.len(), 2);
        let sphere_alive = |m: &Mesh| {
            faces.iter().copied().filter(|&f| {
                m.faces.get(f).map_or(false, |x| {
                    x.is_active()
                        && matches!(
                            x.surface(),
                            Some(crate::surfaces::AnalyticSurface::Sphere { .. })
                        )
                })
            }).count()
        };
        // Run BOTH coplanar re-derive entry points on the equator plane (z=0) — the
        // exact scan a coplanar rect/circle draw triggers. `_analytic_scoped` is the
        // one Scene::intersect_faces_inner actually calls; `rebuild_coplanar_faces`
        // is the legacy bridge. Both must protect the curved hemispheres.
        let _ = crate::operations::face_rederive::rebuild_coplanar_faces(
            &mut mesh, DVec3::ZERO, DVec3::Z, 1.5e-3,
        );
        assert_eq!(sphere_alive(&mesh), 2, "hemispheres survive rebuild_coplanar_faces");
        let _ = crate::operations::face_rederive::rebuild_coplanar_faces_analytic_scoped(
            &mut mesh, DVec3::ZERO, DVec3::Z, 1.5e-3, false, None,
        );
        assert_eq!(sphere_alive(&mesh), 2, "hemispheres survive rebuild_coplanar_faces_analytic_scoped");
        assert!(mesh.verify_face_invariants().is_valid(), "sphere still valid");
    }

    #[test]
    fn adr121_path_b_sphere_total_area_matches_analytic() {
        // 2 hemispheres = full sphere area = 4πr²
        let r = 5.0;
        let expected_full = 4.0 * std::f64::consts::PI * r * r;
        let mut mesh = Mesh::new();
        let faces = mesh.create_sphere_kernel_native(
            DVec3::ZERO, r, MaterialId::new(0),
        ).unwrap();
        let total: f64 = faces.iter().map(|&f| mesh.face_area(f)).sum();
        // Allow 1% tolerance for analytic integration accuracy
        let rel_err = (total - expected_full).abs() / expected_full;
        assert!(rel_err < 0.01,
            "Sphere total area = 4πr² = {}, got {} (rel err {:.4})",
            expected_full, total, rel_err);
    }

    #[test]
    fn adr121_path_b_cone_side_face_area_non_zero() {
        let mut mesh = Mesh::new();
        let faces = mesh.create_cone_kernel_native(
            DVec3::ZERO, 5.0, 10.0, MaterialId::new(0),
        ).unwrap();
        // faces[0] = base disk (Plane), faces[1] = cone side (Cone)
        let side_area = mesh.face_area(faces[1]);
        assert!(side_area > 0.0,
            "Path B cone side face area must be > 0 (got {})", side_area);
    }

    #[test]
    fn adr121_path_b_torus_face_area_non_zero() {
        let mut mesh = Mesh::new();
        let face_id = mesh.create_torus_kernel_native(
            DVec3::ZERO, 10.0, 3.0, MaterialId::new(0),
        ).unwrap();
        let area = mesh.face_area(face_id);
        assert!(area > 0.0,
            "Path B torus face area must be > 0 (got {})", area);

        // Torus surface area first-order = 4π² × R × r
        let expected = 4.0 * std::f64::consts::PI * std::f64::consts::PI * 10.0 * 3.0;
        let rel_err = (area - expected).abs() / expected;
        // First-order approximation tolerance
        assert!(rel_err < 0.05,
            "Torus area ~ 4π²Rr = {}, got {} (rel err {:.4})",
            expected, area, rel_err);
    }

    #[test]
    fn adr121_polygon_face_area_unchanged() {
        // Regression: polygon face Newell path unchanged.
        let mut mesh = Mesh::new();
        let v0 = mesh.add_vertex(DVec3::new(0.0, 0.0, 0.0));
        let v1 = mesh.add_vertex(DVec3::new(2.0, 0.0, 0.0));
        let v2 = mesh.add_vertex(DVec3::new(2.0, 3.0, 0.0));
        let v3 = mesh.add_vertex(DVec3::new(0.0, 3.0, 0.0));
        let fid = mesh.add_face(&[v0, v1, v2, v3], MaterialId::new(0)).unwrap();
        let area = mesh.face_area(fid);
        assert!((area - 6.0).abs() < 1e-9,
            "polygon Newell path unchanged (expected 6.0, got {})", area);
    }

    #[test]
    fn adr253_p1_bezier_patch_area_via_tessellation() {
        // ADR-253 P1 / ADR-192 §3.2(c) — free-form analytic surfaces
        // (Bezier/BSpline/NURBS) previously returned area 0.0 (XIA Inspector
        // "면적 0"). A flat BezierPatch spanning a 10×10 square must now
        // report ~100 via the tessellation triangle-sum fallback.
        let surface = crate::surfaces::AnalyticSurface::BezierPatch {
            ctrl_grid: vec![
                vec![DVec3::new(0.0, 0.0, 0.0), DVec3::new(0.0, 10.0, 0.0)],
                vec![DVec3::new(10.0, 0.0, 0.0), DVec3::new(10.0, 10.0, 0.0)],
            ],
        };
        let area = Mesh::analytic_face_area(&surface);
        assert!((area - 100.0).abs() < 1e-6,
            "flat BezierPatch area must be ~100 via tessellation (got {})", area);
    }

    #[test]
    fn adr253_p1_curved_bspline_surface_area_nonzero() {
        // ADR-253 P1 — a non-flat BSplineSurface (one lifted control point)
        // must report a strictly positive tessellated area, never 0.0.
        let surface = crate::surfaces::AnalyticSurface::BSplineSurface {
            ctrl_grid: vec![
                vec![DVec3::new(0.0, 0.0, 0.0), DVec3::new(0.0, 10.0, 0.0)],
                vec![DVec3::new(10.0, 0.0, 5.0), DVec3::new(10.0, 10.0, 0.0)],
            ],
            knots_u: vec![0.0, 0.0, 1.0, 1.0],
            knots_v: vec![0.0, 0.0, 1.0, 1.0],
            deg_u: 1,
            deg_v: 1,
        };
        let area = Mesh::analytic_face_area(&surface);
        assert!(area > 100.0,
            "curved BSplineSurface area must exceed flat 100 (got {})", area);
    }

    #[test]
    fn adr253_p1_circle_disk_face_area_is_pi_r_squared() {
        // ADR-253 P1 — a Path B cylinder base is a closed-Circle planar disk.
        // Its area must be the ENCLOSED disk area πr², not (2r)² (= the Plane
        // parameter rectangle the analytic branch reported before the
        // closed-curve enclosed-area fix).
        let mut mesh = Mesh::new();
        mesh.set_cylinder_path_b_default(true);
        let faces = mesh
            .create_cylinder(DVec3::ZERO, 5.0, 10.0, 16, MaterialId::new(0))
            .unwrap();
        // faces[0] = base disk (closed-Circle Plane).
        let base_area = mesh.face_area(faces[0]);
        let expected = std::f64::consts::PI * 25.0; // π·r²
        assert!((base_area - expected).abs() < 1e-6,
            "cylinder base disk area must be πr² = {} (got {})", expected, base_area);
        // Regression guard: must NOT be the (2r)² = 100 parameter-rectangle.
        assert!((base_area - 100.0).abs() > 1.0,
            "base area must not be the (2r)² over-report (got {})", base_area);
    }

    /// ADR-257 β-3 — split a Path B cylinder side face by a geodesic porthole
    /// (via split_cylinder_face_by_circle): cap + remainder, manifold, both
    /// inherit Cylinder, cap normal radially outward, 2 faces per loop edge.
    #[test]
    fn adr257_beta3_split_cylinder_manifold_surface_outward() {
        use crate::surfaces::{cylinder, AnalyticSurface};
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        mesh.set_cylinder_path_b_default(true);
        let faces = mesh.create_cylinder(DVec3::ZERO, 10.0, 20.0, 16, mat).expect("cylinder");
        let annulus = faces[2];
        let cyl = mesh.face_surface(annulus).cloned().expect("surface");
        let (ax_o, ax_d, rad, refd, vlo, vhi) = match &cyl {
            AnalyticSurface::Cylinder { axis_origin, axis_dir, radius, ref_dir, v_range, .. } =>
                (*axis_origin, *axis_dir, *radius, *ref_dir, v_range.0, v_range.1),
            _ => panic!("Cylinder, got {:?}", cyl),
        };
        let faces_before = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        let vmid = 0.5 * (vlo + vhi);
        let cp = cylinder::evaluate(ax_o, ax_d, rad, refd, 0.0, vmid);
        let rp = cylinder::evaluate(ax_o, ax_d, rad, refd, 0.4, vmid);
        let samples = cylinder::circle_on_cylinder(ax_o, ax_d, rad, refd, cp, rp, 0.05)
            .expect("geodesic circle");

        let (cap, host) = mesh
            .split_cylinder_face_by_circle(annulus, &samples)
            .expect("split must succeed");
        assert_eq!(host, annulus, "remainder is the host face");

        // cap added exactly once.
        let faces_after = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        assert_eq!(faces_after, faces_before + 1, "split adds exactly 1 face (cap)");

        // manifold (I1-I5).
        let report = mesh.verify_face_invariants();
        assert!(report.is_valid(), "manifold after split: {:?}",
            report.violations.iter().take(4).collect::<Vec<_>>());

        // surface inheritance both sides (ADR-089 A-χ).
        assert!(matches!(mesh.face_surface(cap), Some(AnalyticSurface::Cylinder { .. })),
            "cap inherits Cylinder");
        assert!(matches!(mesh.face_surface(host), Some(AnalyticSurface::Cylinder { .. })),
            "host stays Cylinder");

        // cap normal points radially OUTWARD (at the porthole center).
        let (_s, uc, _v) = cylinder::project_to_cylinder(ax_o, ax_d, rad, refd, cp).unwrap();
        let outward = cylinder::normal(ax_o, ax_d, refd, uc, 0.0);
        assert!(mesh.faces[cap].normal().dot(outward) > 0.0,
            "cap normal must point radially outward (got {:?})", mesh.faces[cap].normal());

        // each cap loop edge bears exactly 2 active faces (N-edge twin ring).
        let cap_hes = mesh.collect_loop_hes(mesh.faces[cap].outer().start).unwrap();
        for he in &cap_hes {
            let eid = mesh.hes[*he].edge();
            let (sharing, _) = mesh.get_faces_sharing_edge(eid);
            let active = sharing.iter()
                .filter(|&&f| mesh.faces.get(f).map(|x| x.is_active()).unwrap_or(false))
                .count();
            assert_eq!(active, 2, "cap loop edge must bear 2 faces (got {})", active);
        }
    }

    /// ADR-284 α (de-risk sim) — the curved-face split is SHAPE-AGNOSTIC: it
    /// splits a curved face by ANY closed on-surface polyline, not just a circle.
    /// `split_cylinder_face_by_circle` (misnomer — it's a closed-polyline
    /// splitter) is fed a RECT-shaped geodesic loop (4 corners unrolled in flat
    /// UV + edge-sampled, exactly how a rect / freehand / bezier-closed shape
    /// would project) → cap + remainder, manifold, Cylinder inherited. This
    /// proves S6 (crossing/closed shape on a curved face) + closed freehand /
    /// bezier reuse the EXISTING split; the only new work is the projection of a
    /// non-circle shape + the tool dispatch (ADR-284 β). (S3 open line = Phase 2.)
    #[test]
    fn adr284_sim_rect_polyline_on_cylinder_splits() {
        use crate::surfaces::{cylinder, AnalyticSurface};
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        mesh.set_cylinder_path_b_default(true);
        let faces = mesh.create_cylinder(DVec3::ZERO, 10.0, 20.0, 16, mat).expect("cylinder");
        let annulus = faces[2];
        let cyl = mesh.face_surface(annulus).cloned().expect("surface");
        let (ax_o, ax_d, rad, refd, vlo, vhi) = match &cyl {
            AnalyticSurface::Cylinder { axis_origin, axis_dir, radius, ref_dir, v_range, .. } =>
                (*axis_origin, *axis_dir, *radius, *ref_dir, v_range.0, v_range.1),
            _ => panic!("Cylinder"),
        };
        let faces_before = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();

        // A small RECT on the cylinder wall: 4 world corners (as a draw tool
        // would capture them), projected + geodesically sampled by the real
        // β-1 `polyline_on_cylinder` (closed).
        let vmid = 0.5 * (vlo + vhi);
        let (du, dv) = (0.30_f64, 3.0_f64); // small angular + height half-extents
        let corners: Vec<DVec3> = [(-du, -dv), (du, -dv), (du, dv), (-du, dv)]
            .iter()
            .map(|&(u, w)| cylinder::evaluate(ax_o, ax_d, rad, refd, u, vmid + w))
            .collect();
        let samples = cylinder::polyline_on_cylinder(ax_o, ax_d, rad, refd, &corners, true, 0.5)
            .expect("rect polyline projects onto the cylinder");

        let (cap, host) = mesh
            .split_cylinder_face_by_circle(annulus, &samples)
            .expect("rect-polyline split must succeed (split is shape-agnostic)");
        assert_eq!(host, annulus, "remainder is the host face");
        let faces_after = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        assert_eq!(faces_after, faces_before + 1, "split adds exactly 1 face (cap)");
        assert!(mesh.verify_face_invariants().is_valid(), "manifold after rect-polyline split");
        assert!(matches!(mesh.face_surface(cap), Some(AnalyticSurface::Cylinder { .. })),
            "cap inherits Cylinder (ADR-089 A-χ)");
    }

    /// ADR-284 β-1 (cone) — a rect polyline projected onto a cone side face
    /// (via `cone::polyline_on_cone`) splits it → cap + remainder, manifold,
    /// Cone inherited. Mirror of the cylinder sim; cone is developable too.
