    /// ADR-284 β-4 (characterization sim) — measure the BOUNDARY structure of
    /// curved faces so we know what "open line rim-to-rim" must attach to. Prints
    /// each curved face's outer-loop HE count + surface kind + inner count.
    /// Expectation (drives the β-4 design): hemisphere / cone-side / cylinder-side
    /// / torus boundaries are self-loop (1-HE) analytic rims — an open chain must
    /// SPLIT that self-loop rim at its 2 endpoints (a NEW surface-aware op; the
    /// planar `split_face_by_chain` polygonizes the rim → loses the surface).
    #[test]
    fn adr284_sim_curved_face_boundary_characterization() {
        use crate::surfaces::AnalyticSurface;
        let dump = |mesh: &Mesh, fid: FaceId, tag: &str| {
            let f = mesh.faces.get(fid).unwrap();
            let hes = mesh.collect_loop_hes(f.outer().start).map(|h| h.len()).unwrap_or(0);
            let vs = mesh.collect_loop_verts(f.outer().start).map(|v| v.len()).unwrap_or(0);
            let kind = match f.surface() {
                Some(AnalyticSurface::Sphere { .. }) => "Sphere",
                Some(AnalyticSurface::Cylinder { .. }) => "Cylinder",
                Some(AnalyticSurface::Cone { .. }) => "Cone",
                Some(AnalyticSurface::Torus { .. }) => "Torus",
                Some(AnalyticSurface::Plane { .. }) => "Plane",
                _ => "None/other",
            };
            eprintln!("[β-4 char] {tag}: outer_hes={hes} outer_verts={vs} surface={kind} inners={}", f.inners().len());
        };
        let mat = MaterialId::new(0);
        // Sphere → 2 hemisphere faces (share the equator self-loop).
        let mut sm = Mesh::new();
        let sf = sm.create_sphere_kernel_native(DVec3::ZERO, 10.0, mat).unwrap();
        for (i, &f) in sf.iter().enumerate() { dump(&sm, f, &format!("sphere.face[{i}]")); }
        // Cylinder Path B → base / top / side annulus.
        let mut cm = Mesh::new();
        cm.set_cylinder_path_b_default(true);
        let cf = cm.create_cylinder(DVec3::ZERO, 10.0, 20.0, 16, mat).unwrap();
        for (i, &f) in cf.iter().enumerate() { dump(&cm, f, &format!("cyl.face[{i}]")); }
        // Cone Path B → base / side.
        let mut km = Mesh::new();
        let kf = km.create_cone_kernel_native(DVec3::ZERO, 5.0, 20.0, mat).unwrap();
        for (i, &f) in kf.iter().enumerate() { dump(&km, f, &format!("cone.face[{i}]")); }
        // Torus → single face.
        let mut tm = Mesh::new();
        let tf = tm.create_torus_kernel_native(DVec3::ZERO, 10.0, 3.0, mat).unwrap();
        dump(&tm, tf, "torus.face");
        // No assertion — this is a measurement probe (run with --nocapture).
        assert!(!sf.is_empty() && !cf.is_empty() && !kf.is_empty());
    }

    /// ADR-284 β-4 (de-risk sim) — does the EXISTING `split_circle_face_by_chord`
    /// (planar: trim rim into arcs → straight chord → split_face_by_chain) work
    /// on a CURVED hemisphere face (equator = circle boundary + Sphere surface)?
    /// This probes how much of "open line rim-to-rim" already exists. Measures
    /// the resulting face count, manifold validity, and whether the sub-faces
    /// keep the Sphere surface. Findings drive the β-4 design (geodesic seam +
    /// surface-preserving sub-faces vs the straight-chord planar result).
    #[test]
    fn adr284_sim_open_chord_on_hemisphere_probe() {
        use crate::surfaces::AnalyticSurface;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let sf = mesh.create_sphere_kernel_native(DVec3::ZERO, 10.0, mat).unwrap();
        let hemi = sf[0];
        let before = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        // Two equator points (z=0 plane): A=(10,0,0), B=(-10,0,0).
        let a = DVec3::new(10.0, 0.0, 0.0);
        let b = DVec3::new(-10.0, 0.0, 0.0);
        let res = mesh.split_circle_face_by_chord(hemi, &[a, b], mat);
        let after = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        let inv = mesh.verify_face_invariants();
        // How many result faces inherit the Sphere surface?
        let sphere_faces = mesh.faces.iter()
            .filter(|(_, f)| f.is_active() && matches!(f.surface(), Some(AnalyticSurface::Sphere { .. })))
            .count();
        eprintln!(
            "[β-4 chord probe] res={:?} faces {}→{} inv_valid={} viol={} sphere_faces={}",
            res.as_ref().map(|o| o.as_ref().map(|v| v.len())),
            before, after, inv.is_valid(), inv.violations.len(), sphere_faces,
        );
        // Probe only — no hard assertion on the split shape (findings documented).
        assert!(res.is_ok(), "split_circle_face_by_chord must not error on a hemisphere");
    }

    /// ADR-284 β-4-1 — SHARED-equator rim-to-rim split of a Path B hemisphere by
    /// an open drawn seam. The equator is a self-loop edge SHARED by both
    /// hemispheres, so the standalone-circle trim breaks the twin (finding
    /// 780a050); [`Mesh::split_sphere_face_by_open_seam`] handles it by trimming
    /// the host + rebuilding the twin + splitting the host by the interior seam.
    /// Locks: 3 result faces, manifold-valid, all inherit Sphere (host twin +
    /// both host pieces).
    #[test]
    fn adr284_beta4_sphere_open_seam_splits_manifold() {
        use crate::surfaces::AnalyticSurface;
        use std::f64::consts::FRAC_PI_2;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let sf = mesh.create_sphere_kernel_native(DVec3::ZERO, 10.0, mat).unwrap();
        let north = sf[0];

        // Equator frame → seam endpoints A,B on the equator + 1 interior point
        // over the north hemisphere (off-surface; the fn projects it).
        let (c, r, n, u) = mesh.circle_of_self_loop_face(north).expect("north circle");
        let vaxis = n.cross(u).normalize();
        let cpt = |ang: f64| c + r * (u * ang.cos() + vaxis * ang.sin());
        let seam = [
            cpt(0.0),                           // rim A (equator)
            DVec3::new(3.0, 3.0, 8.0),          // interior over the hemisphere (z>0)
            cpt(FRAC_PI_2),                     // rim B (equator)
        ];

        let (fa, fb, twin) = mesh
            .split_sphere_face_by_open_seam(north, &seam)
            .expect("open-seam split must succeed on a hemisphere");

        let inv = mesh.verify_face_invariants();
        let faces = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        let sphere_faces = mesh.faces.iter()
            .filter(|(_, f)| f.is_active() && matches!(f.surface(), Some(AnalyticSurface::Sphere { .. })))
            .count();
        assert!(inv.is_valid(), "open-seam split must be manifold: {:?}", inv.violations);
        assert_eq!(faces, 3, "2 host pieces + 1 twin hemisphere");
        assert_eq!(sphere_faces, 3, "all 3 faces inherit Sphere (ADR-089 A-χ)");
        assert_ne!(fa, fb, "two distinct host pieces");
        let twin = twin.expect("a Path B hemisphere has a twin, rebuilt");
        assert!(twin != fa && twin != fb, "twin is distinct from both host pieces");
    }

    /// ADR-284 β-4-1 — reject guards: < 3 seam points (no interior) and a
    /// non-Sphere face are both declined (graceful `None`, no mutation).
    #[test]
    fn adr284_beta4_open_seam_rejects_bad_input() {
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let sf = mesh.create_sphere_kernel_native(DVec3::ZERO, 10.0, mat).unwrap();
        let north = sf[0];
        let (c, r, nrm, u) = mesh.circle_of_self_loop_face(north).unwrap();
        let vaxis = nrm.cross(u).normalize();
        let cpt = |ang: f64| c + r * (u * ang.cos() + vaxis * ang.sin());
        // Only 2 points (no interior) → reject.
        assert!(mesh.split_sphere_face_by_open_seam(north, &[cpt(0.0), cpt(1.0)]).is_none());
        // A planar face → reject.
        let mut pm = Mesh::new();
        let v0 = pm.add_vertex(DVec3::new(0.0, 0.0, 0.0));
        let v1 = pm.add_vertex(DVec3::new(10.0, 0.0, 0.0));
        let v2 = pm.add_vertex(DVec3::new(10.0, 10.0, 0.0));
        let v3 = pm.add_vertex(DVec3::new(0.0, 10.0, 0.0));
        let pf = pm.add_face(&[v0, v1, v2, v3], mat).unwrap();
        let seam = [DVec3::new(0.0, 5.0, 0.0), DVec3::new(5.0, 5.0, 0.0), DVec3::new(10.0, 5.0, 0.0)];
        assert!(pm.split_sphere_face_by_open_seam(pf, &seam).is_none());
    }

    #[test]
    fn adr257_beta3_split_rejects_non_cylinder() {
        // A planar (non-Cylinder) face is rejected.
        let mut mesh = Mesh::new();
        let v0 = mesh.add_vertex(DVec3::new(0.0, 0.0, 0.0));
        let v1 = mesh.add_vertex(DVec3::new(10.0, 0.0, 0.0));
        let v2 = mesh.add_vertex(DVec3::new(10.0, 10.0, 0.0));
        let v3 = mesh.add_vertex(DVec3::new(0.0, 10.0, 0.0));
        let fid = mesh.add_face(&[v0, v1, v2, v3], MaterialId::new(0)).unwrap();
        let samples = vec![
            DVec3::new(2.0, 2.0, 0.0), DVec3::new(4.0, 2.0, 0.0), DVec3::new(3.0, 4.0, 0.0),
        ];
        assert!(mesh.split_cylinder_face_by_circle(fid, &samples).is_none(),
            "non-Cylinder face must be rejected");
    }

    #[test]
    fn adr257_beta3_split_rejects_wrapping_loop() {
        // A loop spanning the full circumference (≥ π from its mean) is the
        // self-overlap case → rejected (β-2 already clamps ρ<πR upstream).
        use crate::surfaces::{cylinder, AnalyticSurface};
        use std::f64::consts::PI;
        let mut mesh = Mesh::new();
        mesh.set_cylinder_path_b_default(true);
        let faces = mesh.create_cylinder(DVec3::ZERO, 10.0, 20.0, 16, MaterialId::new(0)).unwrap();
        let annulus = faces[2];
        let cyl = mesh.face_surface(annulus).cloned().unwrap();
        let (ax_o, ax_d, rad, refd, vlo, vhi) = match &cyl {
            AnalyticSurface::Cylinder { axis_origin, axis_dir, radius, ref_dir, v_range, .. } =>
                (*axis_origin, *axis_dir, *radius, *ref_dir, v_range.0, v_range.1),
            _ => panic!("Cylinder"),
        };
        let vmid = 0.5 * (vlo + vhi);
        let wrap: Vec<DVec3> = [0.0, PI / 2.0, PI, 3.0 * PI / 2.0]
            .iter()
            .map(|&u| cylinder::evaluate(ax_o, ax_d, rad, refd, u, vmid))
            .collect();
        assert!(mesh.split_cylinder_face_by_circle(annulus, &wrap).is_none(),
            "wrapping loop must be rejected (self-overlap guard)");
    }

    #[test]
    fn adr257_beta3_split_rejects_off_surface() {
        // Samples not lying on the cylinder (radius 5 vs cylinder R=10) → None.
        let mut mesh = Mesh::new();
        mesh.set_cylinder_path_b_default(true);
        let faces = mesh.create_cylinder(DVec3::ZERO, 10.0, 20.0, 16, MaterialId::new(0)).unwrap();
        let annulus = faces[2];
        let off = vec![
            DVec3::new(5.0, 0.0, 0.0), DVec3::new(5.0, 1.0, 0.0),
            DVec3::new(4.0, 1.0, 1.0), DVec3::new(4.0, 0.0, 1.0),
        ];
        assert!(mesh.split_cylinder_face_by_circle(annulus, &off).is_none(),
            "off-surface samples must be rejected");
    }

    /// ADR-257 β-4 — after a geodesic-porthole split, the CAP renders bounded
    /// to the porthole (small u-span, all triangles inside the geodesic disk)
    /// and the REMAINDER renders the band MINUS the porthole hole (no triangle
    /// centroid deep inside the porthole) — not the whole cylinder twice.
    #[test]
    fn adr257_beta4_render_cap_bounded_remainder_excludes_porthole() {
        use crate::surfaces::{cylinder, AnalyticSurface};
        use std::f64::consts::{PI, TAU};
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        mesh.set_cylinder_path_b_default(true);
        let faces = mesh.create_cylinder(DVec3::ZERO, 10.0, 20.0, 16, mat).expect("cylinder");
        let annulus = faces[2];
        let (ax_o, ax_d, rad, refd, vlo, vhi) = match mesh.face_surface(annulus).unwrap() {
            AnalyticSurface::Cylinder { axis_origin, axis_dir, radius, ref_dir, v_range, .. } =>
                (*axis_origin, *axis_dir, *radius, *ref_dir, v_range.0, v_range.1),
            _ => panic!("Cylinder"),
        };
        let vmid = 0.5 * (vlo + vhi);
        let cp = cylinder::evaluate(ax_o, ax_d, rad, refd, 0.0, vmid);
        let rp = cylinder::evaluate(ax_o, ax_d, rad, refd, 0.4, vmid);
        let samples = cylinder::circle_on_cylinder(ax_o, ax_d, rad, refd, cp, rp, 0.05)
            .expect("geodesic circle");
        let (cap, host) = mesh
            .split_cylinder_face_by_circle(annulus, &samples)
            .expect("split");

        // porthole center (u, v) + geodesic radius (β-2 unroll = R·Δu = 4mm).
        let (_s, u_ctr, _v) = cylinder::project_to_cylinder(ax_o, ax_d, rad, refd, cp).unwrap();
        let rho = rad * 0.4; // = 4.0 mm
        let geo_dist = |p: DVec3| -> f64 {
            let (_s, u, v) = cylinder::project_to_cylinder(ax_o, ax_d, rad, refd, p).unwrap();
            let mut du = (u - u_ctr).rem_euclid(TAU);
            if du > PI {
                du -= TAU;
            }
            ((rad * du).powi(2) + (v - vmid).powi(2)).sqrt()
        };
        let on_cyl = |p: DVec3| -> f64 {
            let h = (p - ax_o).dot(ax_d.normalize());
            let foot = ax_o + ax_d.normalize() * h;
            ((p - foot).length() - rad).abs()
        };

        // ── CAP: bounded to the porthole disk ──
        let cap_t = mesh
            .tessellate_cylinder_circle_clipped(cap, 0.1)
            .expect("cap renders via circle-clip");
        assert!(!cap_t.triangles.is_empty(), "cap tess non-empty");
        for &v in &cap_t.vertices {
            assert!(on_cyl(v) < 1e-3, "cap vertex on cylinder (radial err {})", on_cyl(v));
        }
        // every cap triangle centroid is INSIDE the geodesic disk (≤ ρ + margin).
        for t in &cap_t.triangles {
            let c = (cap_t.vertices[t[0] as usize]
                + cap_t.vertices[t[1] as usize]
                + cap_t.vertices[t[2] as usize])
                / 3.0;
            assert!(geo_dist(c) < rho + 1.0,
                "cap triangle must lie inside porthole (geo dist {} vs ρ {})", geo_dist(c), rho);
        }
        // cap u-span is small (NOT the whole 2π cylinder).
        let cap_us: Vec<f64> = cap_t.vertices.iter()
            .map(|&p| cylinder::project_to_cylinder(ax_o, ax_d, rad, refd, p).unwrap().1)
            .collect();
        let span = {
            // unwrap around u_ctr to measure span.
            let mut lo = f64::INFINITY;
            let mut hi = f64::NEG_INFINITY;
            for &u in &cap_us {
                let mut du = (u - u_ctr).rem_euclid(TAU);
                if du > PI { du -= TAU; }
                lo = lo.min(du);
                hi = hi.max(du);
            }
            hi - lo
        };
        assert!(span < PI, "cap u-span must be a porthole, not the whole cylinder (got {})", span);

        // ── REMAINDER: band minus the porthole hole ──
        let host_t = mesh
            .tessellate_cylinder_circle_clipped(host, 0.1)
            .expect("remainder renders via circle-clip");
        assert!(!host_t.triangles.is_empty(), "remainder tess non-empty");
        for &v in &host_t.vertices {
            assert!(on_cyl(v) < 1e-3, "remainder vertex on cylinder (radial err {})", on_cyl(v));
        }
        // no remainder triangle centroid is DEEP inside the porthole (the hole
        // is excluded). A whole-cylinder render would have centroids at ~0.
        for t in &host_t.triangles {
            let c = (host_t.vertices[t[0] as usize]
                + host_t.vertices[t[1] as usize]
                + host_t.vertices[t[2] as usize])
                / 3.0;
            assert!(geo_dist(c) > rho * 0.5,
                "remainder triangle must NOT be inside porthole (geo dist {} vs ρ {})",
                geo_dist(c), rho);
        }
    }

    /// ADR-257 β-4 — the α-spec "5-probe de-risk" exit criterion. The belt /
    /// seam-straddle case is the u=0 porthole above (u=0 normalises to a span
    /// crossing the [0,2π) seam). This loops the remaining probes: a non-seam
    /// porthole (u=π, no unwrap), a tiny porthole, and a near-clamp porthole
    /// (u-span just under π). Off-axis robustness composes β-1's project/eval
    /// (axis-agnostic, separately tested) with this axis-agnostic uv earcut.
    #[test]
    fn adr257_beta4_derisk_probes() {
        use crate::surfaces::{cylinder, AnalyticSurface};
        use std::f64::consts::{PI, TAU};
        // (porthole center u, radius u-offset, label)
        let probes = [
            (PI, 0.4, "non-seam"),
            (0.0, 0.1, "tiny"),
            (0.0, 1.5, "near-clamp"),
        ];
        for (uc0, ru, label) in probes {
            let mut mesh = Mesh::new();
            mesh.set_cylinder_path_b_default(true);
            let faces = mesh
                .create_cylinder(DVec3::ZERO, 10.0, 20.0, 16, MaterialId::new(0))
                .unwrap();
            let annulus = faces[2];
            let (ax_o, ax_d, rad, refd, vlo, vhi) = match mesh.face_surface(annulus).unwrap() {
                AnalyticSurface::Cylinder { axis_origin, axis_dir, radius, ref_dir, v_range, .. } =>
                    (*axis_origin, *axis_dir, *radius, *ref_dir, v_range.0, v_range.1),
                _ => panic!("Cylinder"),
            };
            let vmid = 0.5 * (vlo + vhi);
            let cp = cylinder::evaluate(ax_o, ax_d, rad, refd, uc0, vmid);
            let rp = cylinder::evaluate(ax_o, ax_d, rad, refd, uc0 + ru, vmid);
            let samples = cylinder::circle_on_cylinder(ax_o, ax_d, rad, refd, cp, rp, 0.05)
                .unwrap_or_else(|| panic!("{}: geodesic circle", label));
            let (cap, host) = mesh
                .split_cylinder_face_by_circle(annulus, &samples)
                .unwrap_or_else(|| panic!("{}: split", label));

            let (_s, u_ctr, _v) =
                cylinder::project_to_cylinder(ax_o, ax_d, rad, refd, cp).unwrap();
            let rho = rad * ru;
            let geo = |p: DVec3| -> f64 {
                let (_s, u, v) = cylinder::project_to_cylinder(ax_o, ax_d, rad, refd, p).unwrap();
                let mut du = (u - u_ctr).rem_euclid(TAU);
                if du > PI { du -= TAU; }
                ((rad * du).powi(2) + (v - vmid).powi(2)).sqrt()
            };
            let on = |p: DVec3| -> f64 {
                let h = (p - ax_o).dot(ax_d.normalize());
                ((p - (ax_o + ax_d.normalize() * h)).length() - rad).abs()
            };

            let cap_t = mesh.tessellate_cylinder_circle_clipped(cap, 0.1)
                .unwrap_or_else(|| panic!("{}: cap render", label));
            assert!(!cap_t.triangles.is_empty(), "{}: cap non-empty", label);
            for &v in &cap_t.vertices {
                assert!(on(v) < 1e-3, "{}: cap vert on cylinder ({})", label, on(v));
            }
            for t in &cap_t.triangles {
                let c = (cap_t.vertices[t[0] as usize] + cap_t.vertices[t[1] as usize]
                    + cap_t.vertices[t[2] as usize]) / 3.0;
                assert!(geo(c) < rho + 1.5, "{}: cap inside porthole ({} vs {})", label, geo(c), rho);
            }

            let host_t = mesh.tessellate_cylinder_circle_clipped(host, 0.1)
                .unwrap_or_else(|| panic!("{}: remainder render", label));
            assert!(!host_t.triangles.is_empty(), "{}: remainder non-empty", label);
            for &v in &host_t.vertices {
                assert!(on(v) < 1e-3, "{}: remainder vert on cylinder ({})", label, on(v));
            }
            for t in &host_t.triangles {
                let c = (host_t.vertices[t[0] as usize] + host_t.vertices[t[1] as usize]
                    + host_t.vertices[t[2] as usize]) / 3.0;
                assert!(geo(c) > rho * 0.5,
                    "{}: remainder excludes porthole ({} vs {})", label, geo(c), rho);
            }
            // manifold preserved for every probe.
            assert!(mesh.verify_face_invariants().is_valid(), "{}: manifold", label);
        }
    }

    #[test]
    fn adr257_beta4_render_none_for_plain_cylinder() {
        // A plain Path B cylinder side (self-loop Circle boundaries, no
        // geodesic split) must fall through (None) → default tessellation.
        let mut mesh = Mesh::new();
        mesh.set_cylinder_path_b_default(true);
        let faces = mesh.create_cylinder(DVec3::ZERO, 10.0, 20.0, 16, MaterialId::new(0)).unwrap();
        assert!(mesh.tessellate_cylinder_circle_clipped(faces[2], 0.1).is_none(),
            "un-split cylinder side must fall through to default tessellation");
    }

    // ── ADR-263 β-2 (P3-C) — Cone wall circle split + render ──────────────

    /// Helper: build a kernel-native cone and return (mesh, cone_side_face,
    /// apex, axis_dir, half_angle, ref_dir, v_lo, v_hi).
    fn adr263_cone_fixture() -> (Mesh, FaceId, DVec3, DVec3, f64, DVec3, f64, f64) {
        use crate::surfaces::AnalyticSurface;
        let mut mesh = Mesh::new();
        let faces = mesh
            .create_cone_kernel_native(DVec3::ZERO, 10.0, 20.0, MaterialId::new(0))
            .expect("cone");
        let side = faces
            .iter()
            .copied()
            .find(|&f| matches!(mesh.face_surface(f), Some(AnalyticSurface::Cone { .. })))
            .expect("cone side face");
        let (apex, ad, ha, rd, vlo, vhi) = match mesh.face_surface(side).cloned().unwrap() {
            AnalyticSurface::Cone { apex, axis_dir, half_angle, ref_dir, v_range, .. } =>
                (apex, axis_dir, half_angle, ref_dir, v_range.0, v_range.1),
            _ => unreachable!(),
        };
        (mesh, side, apex, ad, ha, rd, vlo, vhi)
    }

    #[test]
    fn adr263_beta2_split_cone_manifold_surface_outward() {
        use crate::surfaces::{cone, AnalyticSurface};
        let (mut mesh, side, apex, ad, ha, rd, vlo, vhi) = adr263_cone_fixture();
        let vmid = 0.5 * (vlo + vhi);
        let cp = cone::evaluate(apex, ad, ha, rd, 0.0, vmid);
        let rp = cone::evaluate(apex, ad, ha, rd, 0.4, vmid);
        let samples = cone::circle_on_cone(apex, ad, ha, rd, cp, rp, 0.05).expect("geodesic circle");

        let before = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        let (cap, host) = mesh.split_cone_face_by_circle(side, &samples).expect("split");
        assert_eq!(host, side, "remainder is the host face");
        let after = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        assert_eq!(after, before + 1, "split adds exactly 1 face (cap)");

        let report = mesh.verify_face_invariants();
        assert!(report.is_valid(), "manifold after cone split: {:?}",
            report.violations.iter().take(4).collect::<Vec<_>>());

        // both inherit the Cone surface (ADR-089 A-χ).
        assert!(matches!(mesh.face_surface(cap), Some(AnalyticSurface::Cone { .. })), "cap = Cone");
        assert!(matches!(mesh.face_surface(host), Some(AnalyticSurface::Cone { .. })), "host = Cone");
        // host gained exactly one inner hole (the porthole).
        assert_eq!(mesh.faces[host].inners().len(), 1, "host gains 1 inner hole");

        // cap normal radially outward at the porthole center.
        let (_s, uc, vcp) = cone::project_to_cone(apex, ad, ha, rd, cp).unwrap();
        let outward = cone::normal(apex, ad, ha, rd, uc, vcp);
        assert!(mesh.faces[cap].normal().dot(outward) > 0.0,
            "cap normal must point outward (got {:?})", mesh.faces[cap].normal());

        // each cap loop edge bears exactly 2 active faces (N-edge twin ring).
        let cap_hes = mesh.collect_loop_hes(mesh.faces[cap].outer().start).unwrap();
        for he in &cap_hes {
            let eid = mesh.hes[*he].edge();
            let (sharing, _) = mesh.get_faces_sharing_edge(eid);
            let active = sharing.iter()
                .filter(|&&f| mesh.faces.get(f).map(|x| x.is_active()).unwrap_or(false))
                .count();
            assert_eq!(active, 2, "cap loop edge must bear 2 faces (got {})", active);
        }
    }

    #[test]
    fn adr263_beta2_render_cap_and_remainder_on_cone() {
        use crate::surfaces::cone;
        let (mut mesh, side, apex, ad, ha, rd, vlo, vhi) = adr263_cone_fixture();
        let vmid = 0.5 * (vlo + vhi);
        let cp = cone::evaluate(apex, ad, ha, rd, 0.0, vmid);
        let rp = cone::evaluate(apex, ad, ha, rd, 0.4, vmid);
        let samples = cone::circle_on_cone(apex, ad, ha, rd, cp, rp, 0.05).unwrap();
        let (cap, host) = mesh.split_cone_face_by_circle(side, &samples).unwrap();

        let cap_t = mesh.tessellate_cone_circle_clipped(cap, 0.1).expect("cap clipped");
        let host_t = mesh.tessellate_cone_circle_clipped(host, 0.1).expect("remainder clipped");
        assert!(!cap_t.triangles.is_empty() && !host_t.triangles.is_empty(), "both non-empty");

        // every rendered vertex lies on the cone surface. Use the cone equation
        // (radial_dist ≈ |axial|·tan α) — apex-safe (the remainder band reaches
        // the apex at v=0, which `project_to_cone` cannot invert, by design).
        let axis_n = ad.normalize_or_zero();
        for v in cap_t.vertices.iter().chain(host_t.vertices.iter()) {
            let axial = (*v - apex).dot(axis_n);
            let foot = apex + axis_n * axial;
            let radial = (*v - foot).length();
            let expected = axial.abs() * ha.tan();
            assert!((radial - expected).abs() < 1e-4,
                "vertex off cone: radial {} vs expected {} at {:?}", radial, expected, v);
        }
    }

    #[test]
    fn adr263_beta2_render_none_for_plain_cone() {
        // A plain kernel-native cone side (no geodesic split) → None (default).
        let (mesh, side, ..) = adr263_cone_fixture();
        assert!(mesh.tessellate_cone_circle_clipped(side, 0.1).is_none(),
            "un-split cone side must fall through to default tessellation");
    }

    #[test]
    fn adr263_beta2_split_rejects_non_cone_and_off_surface() {
        use crate::surfaces::cone;
        // Non-Cone (planar) host → None.
        let mut pm = Mesh::new();
        let v0 = pm.add_vertex(DVec3::ZERO);
        let v1 = pm.add_vertex(DVec3::new(10.0, 0.0, 0.0));
        let v2 = pm.add_vertex(DVec3::new(10.0, 10.0, 0.0));
        let v3 = pm.add_vertex(DVec3::new(0.0, 10.0, 0.0));
        let pf = pm.add_face(&[v0, v1, v2, v3], MaterialId::new(0)).unwrap();
        let dummy = vec![DVec3::ZERO, DVec3::X, DVec3::Y];
        assert!(pm.split_cone_face_by_circle(pf, &dummy).is_none(), "non-Cone host → None");

        // Off-surface samples (not on the cone) → None.
        let (mut mesh, side, apex, ad, ha, rd, vlo, vhi) = adr263_cone_fixture();
        let vmid = 0.5 * (vlo + vhi);
        // a small planar square far from the cone surface.
        let off: Vec<DVec3> = (0..8).map(|i| {
            let t = std::f64::consts::TAU * (i as f64) / 8.0;
            apex + DVec3::new(t.cos(), t.sin(), 0.0) * 0.5 + ad.normalize_or_zero() * vmid
        }).collect();
        assert!(mesh.split_cone_face_by_circle(side, &off).is_none(),
            "off-surface samples must be rejected");
    }

    // ── ADR-263 β-5 (P3-C) — Torus wall circle split + render ─────────────

    /// Helper: build a kernel-native torus and return (mesh, torus_face,
    /// center, axis_dir, ref_dir, major_radius, minor_radius).
    fn adr263_torus_fixture() -> (Mesh, FaceId, DVec3, DVec3, DVec3, f64, f64) {
        use crate::surfaces::AnalyticSurface;
        let mut mesh = Mesh::new();
        let face = mesh
            .create_torus_kernel_native(DVec3::ZERO, 500.0, 100.0, MaterialId::new(0))
            .expect("torus");
        let (c, ad, rd, mr, nr) = match mesh.face_surface(face).cloned().unwrap() {
            AnalyticSurface::Torus { center, axis_dir, ref_dir, major_radius, minor_radius, .. } =>
                (center, axis_dir, ref_dir, major_radius, minor_radius),
            _ => panic!("Torus surface"),
        };
        (mesh, face, c, ad, rd, mr, nr)
    }

    #[test]
    fn adr263_beta5_split_torus_manifold_surface_outward() {
        use crate::surfaces::{torus, AnalyticSurface};
        let (mut mesh, side, c, ad, rd, mr, nr) = adr263_torus_fixture();
        let cp = torus::evaluate(c, ad, rd, mr, nr, 0.3, 0.5);
        let rp = torus::evaluate(c, ad, rd, mr, nr, 0.5, 0.8);
        let samples = torus::circle_on_torus(c, ad, rd, mr, nr, cp, rp, 0.05).expect("porthole");

        let before = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        let (cap, host) = mesh.split_torus_face_by_circle(side, &samples).expect("split");
        assert_eq!(host, side, "remainder is the host face");
        let after = mesh.faces.iter().filter(|(_, f)| f.is_active()).count();
        assert_eq!(after, before + 1, "split adds exactly 1 face (cap)");

        let report = mesh.verify_face_invariants();
        assert!(report.is_valid(), "manifold after torus split: {:?}",
            report.violations.iter().take(4).collect::<Vec<_>>());

        assert!(matches!(mesh.face_surface(cap), Some(AnalyticSurface::Torus { .. })), "cap = Torus");
        assert!(matches!(mesh.face_surface(host), Some(AnalyticSurface::Torus { .. })), "host = Torus");
        assert_eq!(mesh.faces[host].inners().len(), 1, "host gains 1 inner hole");

        let (_s, uc, vc) = torus::project_to_torus(c, ad, rd, mr, nr, cp).unwrap();
        let outward = torus::normal(c, ad, rd, mr, nr, uc, vc);
        assert!(mesh.faces[cap].normal().dot(outward) > 0.0,
            "cap normal must point outward (got {:?})", mesh.faces[cap].normal());

        let cap_hes = mesh.collect_loop_hes(mesh.faces[cap].outer().start).unwrap();
        for he in &cap_hes {
            let eid = mesh.hes[*he].edge();
            let (sharing, _) = mesh.get_faces_sharing_edge(eid);
            let active = sharing.iter()
                .filter(|&&f| mesh.faces.get(f).map(|x| x.is_active()).unwrap_or(false))
                .count();
            assert_eq!(active, 2, "cap loop edge must bear 2 faces (got {})", active);
        }
    }

    #[test]
    fn adr263_beta5_render_cap_and_remainder_on_torus() {
        use crate::surfaces::torus;
        let (mut mesh, side, c, ad, rd, mr, nr) = adr263_torus_fixture();
        let cp = torus::evaluate(c, ad, rd, mr, nr, 0.3, 0.5);
        let rp = torus::evaluate(c, ad, rd, mr, nr, 0.5, 0.8);
        let samples = torus::circle_on_torus(c, ad, rd, mr, nr, cp, rp, 0.05).unwrap();
        let (cap, host) = mesh.split_torus_face_by_circle(side, &samples).unwrap();

        let cap_t = mesh.tessellate_torus_circle_clipped(cap, 0.5).expect("cap clipped");
        let host_t = mesh.tessellate_torus_circle_clipped(host, 0.5).expect("remainder clipped");
        assert!(!cap_t.triangles.is_empty() && !host_t.triangles.is_empty(), "both non-empty");

        // every rendered vertex lies on the torus surface (project round-trips).
        for v in cap_t.vertices.iter().chain(host_t.vertices.iter()) {
            let (sp, _, _) = torus::project_to_torus(c, ad, rd, mr, nr, *v)
                .unwrap_or_else(|| panic!("vertex off torus: {:?}", v));
            assert!((sp - *v).length() < 1e-4, "vertex off torus: {}", (sp - *v).length());
        }
    }

