    #[test]
    fn adr097_t_gamma_clean_mesh_returns_noop() {
        use crate::topology_damage::RecoveryOutcome;
        let mut mesh = Mesh::new();
        let outcome = mesh.attempt_auto_recovery();
        assert!(matches!(outcome, RecoveryOutcome::NoOp),
            "clean mesh → NoOp, got {:?}", outcome.label());
        assert!(outcome.is_success());
    }

    #[test]
    fn adr097_t_gamma_boundary_edge_only_partial_failure() {
        // Single quad face → 4 boundary edges. T-γ 가 BoundaryEdge auto-fix
        // 미시도 → PartialFailure (escalation 대상).
        use crate::topology_damage::RecoveryOutcome;
        let mut mesh = Mesh::new();
        let _ = build_quad_face(&mut mesh);
        let outcome = mesh.attempt_auto_recovery();
        match outcome {
            RecoveryOutcome::PartialFailure { fixes_applied, remaining } => {
                assert_eq!(fixes_applied, 0,
                    "BoundaryEdge auto-fix 미시도 — fixes_applied 0");
                let (be, _, _, _) = remaining.count_by_kind();
                assert_eq!(be, 4, "4 boundary edges 잔존");
            }
            other => panic!("expected PartialFailure, got {:?}", other.label()),
        }
    }

    #[test]
    fn adr097_t_gamma_recovery_outcome_labels_stable() {
        use crate::topology_damage::{RecoveryOutcome, TopologyDamageReport};
        let no_op = RecoveryOutcome::NoOp;
        let recovered = RecoveryOutcome::Recovered {
            fixes_applied: 1, initial_damages: 1,
        };
        let partial = RecoveryOutcome::PartialFailure {
            fixes_applied: 0,
            remaining: TopologyDamageReport {
                damages: vec![], checked_faces: 0, checked_edges: 0,
            },
        };
        assert_eq!(no_op.label(), "NoOp");
        assert_eq!(recovered.label(), "Recovered");
        assert_eq!(partial.label(), "PartialFailure");
        assert!(no_op.is_success());
        assert!(recovered.is_success());
        assert!(!partial.is_success());
    }

    /// **CAD trim (2026-06-15)** — `trim_circle_face_at_crossings` DCEL trim 검증.
    /// circle self-loop face → 수직선이 (0,±r) 가로지름 → 2 Arc → D7 midpoint →
    /// 4 arc edge 경계 면 (폴리곤화 아님). 검증: self-loop 교체 / rim 전부 Arc
    /// (직선 chord 0) / 전부 HARD (분할선 가시, 메타-원칙 #15) / manifold valid /
    /// 매끈 fill (arc tessellation, 4-gon 아님). < 2 crossing → None.
    #[test]
    fn cad_trim_circle_face_produces_arc_boundary() {
        use crate::curves::AnalyticCurve;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let center = DVec3::ZERO;
        let radius = 100.0;
        let anchor = mesh.add_vertex(center + DVec3::X * radius);
        let circle = AnalyticCurve::Circle { center, radius, normal: DVec3::Z, basis_u: DVec3::X };
        let fid = mesh.add_face_closed_curve(anchor, circle, mat).expect("circle face");
        assert_eq!(mesh.faces.iter().filter(|(_, f)| f.is_active()).count(), 1);

        // vertical secant x=0 crosses at (0, ±r).
        let crossings = [DVec3::new(0.0, radius, 0.0), DVec3::new(0.0, -radius, 0.0)];
        let (new_fid, crossing_verts) = mesh
            .trim_circle_face_at_crossings(fid, &crossings, mat)
            .expect("trim ok")
            .expect("trimmed Some");
        let _ = new_fid;
        assert_eq!(crossing_verts.len(), 2, "2 crossings → 2 rim split verts");

        // still 1 disk face, now arc-bounded.
        assert_eq!(mesh.faces.iter().filter(|(_, f)| f.is_active()).count(), 1);

        // boundary: all Arc, no straight chord, no self-loop, all HARD.
        let mut arc = 0usize;
        let mut other = 0usize;
        let mut self_loop = 0usize;
        let mut non_hard = 0usize;
        for (_, e) in mesh.edges.iter() {
            if !e.is_active() {
                continue;
            }
            if e.is_self_loop() {
                self_loop += 1;
            }
            match e.curve() {
                Some(AnalyticCurve::Arc { .. }) => arc += 1,
                _ => other += 1,
            }
            let h = e.any_he();
            if !h.is_null() && !mesh.hes[h].flags().contains(HeFlags::HARD) {
                non_hard += 1;
            }
        }
        assert_eq!(self_loop, 0, "self-loop replaced by arcs");
        assert!(arc >= 4, "≥4 arc segments (2 arcs × D7 midpoint), got {}", arc);
        assert_eq!(other, 0, "rim stays arc (no straight chords), got {}", other);
        assert_eq!(non_hard, 0, "all rim arcs HARD (split lines visible), got {} non-hard", non_hard);

        // manifold valid.
        assert!(mesh.verify_face_invariants().is_valid(), "trimmed face manifold-valid");

        // smooth fill: arc-tessellated, not a flat 4-gon (2 tris).
        let (_, _, indices, _, _) = mesh.export_buffers().expect("export");
        assert!(indices.len() / 3 > 20, "arc face fills smoothly, got {} tris", indices.len() / 3);

        // < 2 distinct crossings → None (keep whole circle).
        let mut m2 = Mesh::new();
        let a2 = m2.add_vertex(center + DVec3::X * radius);
        let c2 = AnalyticCurve::Circle { center, radius, normal: DVec3::Z, basis_u: DVec3::X };
        let f2 = m2.add_face_closed_curve(a2, c2, mat).unwrap();
        assert!(m2
            .trim_circle_face_at_crossings(f2, &[DVec3::new(0.0, radius, 0.0)], mat)
            .unwrap()
            .is_none());
    }

    /// **CAD trim + split (2026-06-15)** — `split_circle_face_by_chord`
    /// end-to-end. circle self-loop face → 수직 secant (0,±r) → trim + chord →
    /// **2 half-disk**. rim 은 arc 보존 (폴리곤화 아님), chord 1개 (직선),
    /// manifold valid, 매끈 fill. = pin-down 버그 (rect 교차 시 rim faceting) 의
    /// surgical fix 의 핵심 연산.
    #[test]
    fn cad_trim_split_circle_into_two_half_disks() {
        use crate::curves::AnalyticCurve;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let center = DVec3::ZERO;
        let radius = 100.0;
        let anchor = mesh.add_vertex(center + DVec3::X * radius);
        let circle = AnalyticCurve::Circle { center, radius, normal: DVec3::Z, basis_u: DVec3::X };
        let fid = mesh.add_face_closed_curve(anchor, circle, mat).expect("circle face");
        assert_eq!(mesh.faces.iter().filter(|(_, f)| f.is_active()).count(), 1);

        // vertical secant x=0 → trim + chord → 2 half-disks.
        let crossings = [DVec3::new(0.0, radius, 0.0), DVec3::new(0.0, -radius, 0.0)];
        let faces = mesh
            .split_circle_face_by_chord(fid, &crossings, mat)
            .expect("split ok")
            .expect("split Some");
        assert_eq!(faces.len(), 2, "secant splits disk into 2 half-disks, got {}", faces.len());
        assert_eq!(mesh.faces.iter().filter(|(_, f)| f.is_active()).count(), 2);

        // rim stays arc (≥4 arc edges across both halves), exactly 1 straight chord.
        let mut arc = 0usize;
        let mut line = 0usize;
        let mut self_loop = 0usize;
        for (_, e) in mesh.edges.iter() {
            if !e.is_active() {
                continue;
            }
            if e.is_self_loop() {
                self_loop += 1;
            }
            match e.curve() {
                Some(AnalyticCurve::Arc { .. }) | Some(AnalyticCurve::Circle { .. }) => arc += 1,
                _ => line += 1, // straight chord (the secant)
            }
        }
        assert_eq!(self_loop, 0, "no self-loop (trimmed)");
        assert!(arc >= 4, "rim preserved as arcs (≥4), got {}", arc);
        assert_eq!(line, 1, "exactly 1 straight chord (the secant), got {}", line);

        // manifold valid + smooth fill (arc-tessellated half-disks, not 3-gons).
        assert!(mesh.verify_face_invariants().is_valid(), "two half-disks manifold-valid");
        let (_, _, indices, _, _) = mesh.export_buffers().expect("export");
        assert!(indices.len() / 3 > 20, "arc half-disks fill smoothly, got {} tris", indices.len() / 3);
    }

    /// **CAD trim (2026-06-15)** — analytic line-driven trim + **order
    /// independence** (사용자 우려: 순서 의존 / 4-호 오검출). A full secant returns
    /// exactly 2 crossings regardless of endpoint order; `split_circle_face_by_
    /// line` splits the disk into 2 the same way either direction. Interior chord
    /// (no rim cross) / missing line → no split (None).
    #[test]
    fn cad_trim_split_circle_by_line_order_independent() {
        use crate::curves::AnalyticCurve;
        let mat = MaterialId::new(0);
        let center = DVec3::ZERO;
        let radius = 100.0;
        let l = DVec3::new(-150.0, 0.0, 0.0);
        let r = DVec3::new(150.0, 0.0, 0.0);

        // analytic crossings: order-independent (swap endpoints → same set).
        let c1 = Mesh::line_segment_circle_crossings(l, r, center, radius, DVec3::Z, DVec3::X);
        let c2 = Mesh::line_segment_circle_crossings(r, l, center, radius, DVec3::Z, DVec3::X);
        assert_eq!(c1.len(), 2, "full secant → exactly 2 crossings (not 4)");
        assert_eq!(c2.len(), 2);
        let key = |v: &[DVec3]| {
            let mut k: Vec<i64> = v.iter().map(|p| (p.x * 1000.0).round() as i64).collect();
            k.sort();
            k
        };
        assert_eq!(key(&c1), key(&c2), "crossings order-independent");
        assert!(c1.iter().any(|p| (p.x - 100.0).abs() < 1e-6 && p.y.abs() < 1e-6), "+x rim");
        assert!(c1.iter().any(|p| (p.x + 100.0).abs() < 1e-6 && p.y.abs() < 1e-6), "-x rim");

        // line-driven split → 2 half-disks, draw-order-independent.
        let split = |p0: DVec3, p1: DVec3| -> usize {
            let mut mesh = Mesh::new();
            let anchor = mesh.add_vertex(center + DVec3::X * radius);
            let circle = AnalyticCurve::Circle { center, radius, normal: DVec3::Z, basis_u: DVec3::X };
            let fid = mesh.add_face_closed_curve(anchor, circle, mat).unwrap();
            mesh.split_circle_face_by_line(fid, p0, p1, mat)
                .unwrap()
                .map_or(0, |f| f.len())
        };
        assert_eq!(split(l, r), 2, "secant L→R → 2");
        assert_eq!(split(r, l), 2, "secant R→L → 2 (order-independent)");
        // interior chord (both endpoints inside disk) → no rim cross → no split.
        assert_eq!(split(DVec3::new(-50.0, 0.0, 0.0), DVec3::new(50.0, 0.0, 0.0)), 0, "interior chord");
        // line entirely above the circle → misses → no split.
        assert_eq!(split(DVec3::new(-150.0, 200.0, 0.0), DVec3::new(150.0, 200.0, 0.0)), 0, "missing line");
    }

    /// Finding #1 (2026-06-16) — `split_edges_at_circle_crossings` breaks an
    /// existing straight edge where the new circle's rim crosses it, so its
    /// tails survive instead of being truncated to the chord (the reverse
    /// direction of DrawLine-over-circle). Diameter line (-120..120) × r=60
    /// circle → 3 segments split at ±60.
    #[test]
    fn finding1_split_edges_at_circle_crossings_breaks_line() {
        let mut mesh = Mesh::new();
        let v0 = mesh.add_vertex(DVec3::new(-120.0, 0.0, 0.0));
        let v1 = mesh.add_vertex(DVec3::new(120.0, 0.0, 0.0));
        mesh.add_edge(v0, v1).unwrap();
        let n = mesh.split_edges_at_circle_crossings(DVec3::ZERO, 60.0, DVec3::Z, DVec3::X);
        assert_eq!(n, 2, "diameter line crosses the rim at ±60 → 2 splits");
        let lines = mesh
            .edges
            .iter()
            .filter(|(_, e)| e.is_active() && e.curve().is_none())
            .count();
        assert_eq!(lines, 3, "line split into 3 segments (2 tails + chord)");
        let has = |x: f64| {
            mesh.verts.iter().any(|(_, v)| {
                v.is_active() && (v.pos().x - x).abs() < 1e-6 && v.pos().y.abs() < 1e-6
            })
        };
        assert!(has(60.0) && has(-60.0), "shared crossing vertices created at ±60");
    }

    /// Finding #1 — `split_edges_at_circle_crossings` is a no-op for a line that
    /// misses the circle (idempotent / order-safe).
    #[test]
    fn finding1_split_edges_at_circle_crossings_noop_when_disjoint() {
        let mut mesh = Mesh::new();
        let v0 = mesh.add_vertex(DVec3::new(-120.0, 200.0, 0.0));
        let v1 = mesh.add_vertex(DVec3::new(120.0, 200.0, 0.0));
        mesh.add_edge(v0, v1).unwrap();
        let n = mesh.split_edges_at_circle_crossings(DVec3::ZERO, 60.0, DVec3::Z, DVec3::X);
        assert_eq!(n, 0, "line far above the circle → no split");
        let lines = mesh
            .edges
            .iter()
            .filter(|(_, e)| e.is_active() && e.curve().is_none())
            .count();
        assert_eq!(lines, 1, "line unchanged");
    }

    /// ADR-264 D3 — the geometric detector returns EMPTY on a clean closed box
    /// (no false positive on a valid solid; the crack-catching positive case is
    /// covered at scene level by `adr264_geometric_detector_catches_cleave_crack`,
    /// since a crack needs coincident-DISTINCT verts that `add_vertex` dedups).
    #[test]
    fn adr264_geometric_detector_clean_on_box() {
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        mesh.create_box(DVec3::ZERO, 1000.0, 1000.0, 1000.0, mat).unwrap();
        assert!(
            mesh.collect_non_manifold_edges_geometric().is_empty(),
            "a clean closed box must have NO geometric non-manifold (no false positive)"
        );
    }

    /// **CAD trim item 4 (2026-06-15)** — `circle_circle_crossings` analytic +
    /// order-independent. Two r=100 circles 150 apart → 2 crossings at x=75,
    /// y=±66.1, on both rims; swapping circles → same set. Disjoint→0,
    /// tangent→1, nested→0.
    #[test]
    fn cad_trim_circle_circle_crossings_order_independent() {
        let c0 = DVec3::ZERO;
        let c1 = DVec3::new(150.0, 0.0, 0.0);
        let r = 100.0;
        let a = Mesh::circle_circle_crossings(c0, r, c1, r, DVec3::Z);
        let b = Mesh::circle_circle_crossings(c1, r, c0, r, DVec3::Z);
        assert_eq!(a.len(), 2, "overlapping circles → 2 crossings");
        assert_eq!(b.len(), 2);
        let key = |v: &[DVec3]| {
            let mut k: Vec<(i64, i64)> = v
                .iter()
                .map(|p| ((p.x * 100.0).round() as i64, (p.y.abs() * 100.0).round() as i64))
                .collect();
            k.sort();
            k
        };
        assert_eq!(key(&a), key(&b), "order-independent (circle swap = same crossings)");
        for p in &a {
            assert!(((*p - c0).length() - r).abs() < 1e-6, "on circle 0");
            assert!(((*p - c1).length() - r).abs() < 1e-6, "on circle 1");
            assert!((p.x - 75.0).abs() < 1e-3, "x=75 (radical line)");
        }
        // disjoint (centers 300 apart, r=100) → 0.
        assert_eq!(
            Mesh::circle_circle_crossings(c0, r, DVec3::new(300.0, 0.0, 0.0), r, DVec3::Z).len(),
            0,
            "disjoint"
        );
        // tangent (centers 200 apart, r=100) → 1.
        assert_eq!(
            Mesh::circle_circle_crossings(c0, r, DVec3::new(200.0, 0.0, 0.0), r, DVec3::Z).len(),
            1,
            "tangent"
        );
        // nested (small circle inside big) → 0.
        assert_eq!(
            Mesh::circle_circle_crossings(c0, 100.0, DVec3::new(10.0, 0.0, 0.0), 50.0, DVec3::Z).len(),
            0,
            "nested"
        );
    }

    /// **CAD trim item 3 (2026-06-15)** — `split_arc_edge_at` inherits sub-arcs.
    /// Split an Arc edge at a point → 2 child Arc edges that stay ON the circle
    /// (radius exact) + cover the original. ADR-059 left split_edge children
    /// curveless; this fixes that for Arc so a line cutting an arc-bounded face
    /// keeps the rim smooth (item 3 foundation).
    #[test]
    fn cad_trim_split_arc_edge_inherits_subarcs() {
        use crate::curves::AnalyticCurve;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let center = DVec3::ZERO;
        let radius = 100.0;
        let anchor = mesh.add_vertex(center + DVec3::X * radius);
        let circle = AnalyticCurve::Circle { center, radius, normal: DVec3::Z, basis_u: DVec3::X };
        let fid = mesh.add_face_closed_curve(anchor, circle, mat).unwrap();
        mesh.trim_circle_face_at_crossings(
            fid,
            &[DVec3::new(0.0, radius, 0.0), DVec3::new(0.0, -radius, 0.0)],
            mat,
        )
        .unwrap()
        .unwrap();

        // pick an arc edge + a point at its arc midpoint.
        let arc_edge = mesh
            .edges
            .iter()
            .find(|(_, e)| e.is_active() && matches!(e.curve(), Some(AnalyticCurve::Arc { .. })))
            .map(|(id, _)| id)
            .expect("arc edge present");
        let (c, r, n, u, sa, ea) = match mesh.edges[arc_edge].curve() {
            Some(AnalyticCurve::Arc { center, radius, normal, basis_u, start_angle, end_angle }) => {
                (*center, *radius, *normal, *basis_u, *start_angle, *end_angle)
            }
            _ => panic!("arc"),
        };
        let bv = n.cross(u).normalize_or_zero();
        let amid = (sa + ea) * 0.5;
        let pmid = c + r * (u * amid.cos() + bv * amid.sin());

        let (vp, e1, e2) = mesh.split_arc_edge_at(arc_edge, pmid).unwrap();

        assert!(matches!(mesh.edges[e1].curve(), Some(AnalyticCurve::Arc { .. })), "child 1 = Arc");
        assert!(matches!(mesh.edges[e2].curve(), Some(AnalyticCurve::Arc { .. })), "child 2 = Arc");
        let pvp = mesh.vertex_pos(vp).unwrap();
        assert!(((pvp - c).length() - r).abs() < 1e-3, "split vertex on rim");

        let tess = |eid: EdgeId, m: &Mesh| -> Vec<DVec3> {
            match m.edges[eid].curve() {
                Some(AnalyticCurve::Arc { center, radius, normal, basis_u, start_angle, end_angle }) => {
                    crate::curves::arc::tessellate(*center, *radius, *normal, *basis_u, *start_angle, *end_angle, 0.1)
                }
                _ => vec![],
            }
        };
        let mut pts = tess(e1, &mesh);
        pts.extend(tess(e2, &mesh));
        assert!(pts.len() >= 6, "both sub-arcs tessellate smoothly, got {}", pts.len());
        for p in &pts {
            assert!(((*p - c).length() - r).abs() < 1e-3, "sub-arc point on rim: {:?}", p);
        }
        assert!(mesh.verify_face_invariants().is_valid(), "manifold valid after arc-edge split");
    }

    /// **ADR-186 step ① (2026-06-16)** — generic `split_edge` now inherits
    /// **free-form** sub-curves. A Bezier wire edge split at an interior point
    /// yields 2 child edges that BOTH carry `Bezier` curves (was: curveless
    /// Lines, curve metadata lost). This is the DCEL-level foundation for
    /// curve × curve / curve × line trim.
    #[test]
    fn step1_split_bezier_edge_inherits_subbeziers() {
        use crate::curves::{AnalyticCurve, CurveOps};
        let mut mesh = Mesh::new();
        // Curved cubic Bezier (control_pts[0] @ v0, [3] @ v3).
        let ctrl = vec![
            DVec3::new(0.0, 0.0, 0.0),
            DVec3::new(10.0, 30.0, 0.0),
            DVec3::new(40.0, 30.0, 0.0),
            DVec3::new(50.0, 0.0, 0.0),
        ];
        let bezier = AnalyticCurve::Bezier { control_pts: ctrl.clone() };
        let v0 = mesh.add_vertex(ctrl[0]);
        let v3 = mesh.add_vertex(ctrl[3]);
        let (eid, created) = mesh.add_edge(v0, v3).unwrap();
        assert!(created, "wire edge created");
        mesh.edges[eid].set_curve(Some(bezier.clone()));

        // Cut at the Bezier's parametric t=0.35 world point.
        let cut = bezier.evaluate(0.35, &mesh).unwrap();
        let (vp, e1, e2) = mesh.split_edge(eid, cut).unwrap();

        // Both children inherit a Bezier (NOT degraded to curveless Line).
        assert!(matches!(mesh.edges[e1].curve(), Some(AnalyticCurve::Bezier { .. })),
            "child e1 must be Bezier, got {:?}", mesh.edges[e1].curve());
        assert!(matches!(mesh.edges[e2].curve(), Some(AnalyticCurve::Bezier { .. })),
            "child e2 must be Bezier, got {:?}", mesh.edges[e2].curve());

        // Split vertex sits on the parent curve.
        let pvp = mesh.vertex_pos(vp).unwrap();
        assert!((pvp - cut).length() < 1e-6, "split vertex on parent curve");

        // Every tessellated point of both children lies on the parent Bezier
        // (shape preserved). Exact analytic on-curve test via the new
        // parameter_at_3d_point projection (Gauss-Newton, tol 1.5e-4 mm) —
        // an Ok result means the point projects onto the parent within tol.
        for &child in &[e1, e2] {
            let pts = mesh.edges[child].curve().unwrap().tessellate(0.05, &mesh).unwrap();
            assert!(pts.len() >= 2, "child tessellates");
            for p in pts {
                assert!(bezier.parameter_at_3d_point(p, &mesh).is_ok(),
                    "child point {:?} not on parent Bezier", p);
            }
        }
    }

    /// **ADR-186 step ③ detector (2026-06-16)** — `freeform_closed_curve_faces_
    /// crossed_by_segment` returns a free-form (Bezier) self-loop face for a
    /// secant line, and nothing for a non-crossing line (so the caller never
    /// seeds a no-op arrange re-derive). Circle self-loops are NOT returned
    /// (the sibling Circle method owns those).
    #[test]
    fn step3_freeform_crossed_detector_secant_only() {
        use crate::curves::AnalyticCurve;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        // closed teardrop Bezier loop (control_pts[0] == [last]).
        let ctrl = vec![
            DVec3::new(50.0, 0.0, 0.0),
            DVec3::new(120.0, 50.0, 0.0),
            DVec3::new(50.0, 100.0, 0.0),
            DVec3::new(-20.0, 50.0, 0.0),
            DVec3::new(50.0, 0.0, 0.0),
        ];
        let anchor = mesh.add_vertex(ctrl[0]);
        let bez = AnalyticCurve::Bezier { control_pts: ctrl };
        let _fid = mesh.add_face_closed_curve(anchor, bez, mat).unwrap();

        // secant line through mid-height → detected.
        let hit = mesh.freeform_closed_curve_faces_crossed_by_segment(
            DVec3::new(-100.0, 50.0, 0.0), DVec3::new(200.0, 50.0, 0.0),
        );
        assert_eq!(hit.len(), 1, "secant line detects the Bezier blob, got {:?}", hit);

        // non-crossing line (well below) → not detected.
        let miss = mesh.freeform_closed_curve_faces_crossed_by_segment(
            DVec3::new(-100.0, -50.0, 0.0), DVec3::new(200.0, -50.0, 0.0),
        );
        assert!(miss.is_empty(), "non-crossing line detects nothing, got {:?}", miss);

        // a Circle self-loop must NOT be returned by the free-form detector.
        let mut m2 = Mesh::new();
        let ca = m2.add_vertex(DVec3::new(100.0, 0.0, 0.0));
        let circ = AnalyticCurve::Circle { center: DVec3::ZERO, radius: 100.0, normal: DVec3::Z, basis_u: DVec3::X };
        let _ = m2.add_face_closed_curve(ca, circ, mat).unwrap();
        let circ_hit = m2.freeform_closed_curve_faces_crossed_by_segment(
            DVec3::new(-200.0, 0.0, 0.0), DVec3::new(200.0, 0.0, 0.0),
        );
        assert!(circ_hit.is_empty(), "Circle is owned by the Circle detector, not free-form");
    }

    /// **CAD trim item 6 (2026-06-15)** — 사용자 진단 "원이 4개 정점 / facet 픽"
    /// 의 근본 = trim 된 rim arc 들이 `curve_owner_id` 그룹 없이 파편화. fix:
    /// `trim_circle_face_at_crossings` 가 rim 호 들에 **공유 owner** 부여 →
    /// ADR-088 grouping (edges_by_curve_owner) 이 rim 을 1 논리 원으로 묶음
    /// (CurveEdgeId{xia,group} = 우리 curve_owner_id). + `split_arc_edge_at` 가
    /// 재분할 시 owner 를 양 child 에 전파 (rim 그룹 유지). Line/Circle 독립.
    #[test]
    fn item6_trim_groups_rim_arcs_by_curve_owner() {
        use crate::curves::AnalyticCurve;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let center = DVec3::ZERO;
        let radius = 100.0;
        let anchor = mesh.add_vertex(center + DVec3::X * radius);
        let circle = AnalyticCurve::Circle { center, radius, normal: DVec3::Z, basis_u: DVec3::X };
        let fid = mesh.add_face_closed_curve(anchor, circle, mat).unwrap();
        // line trim → 4 rim arcs + chord (the user's "4 정점" case).
        mesh.split_circle_face_by_line(
            fid,
            DVec3::new(-150.0, 0.0, 0.0),
            DVec3::new(150.0, 0.0, 0.0),
            mat,
        )
        .unwrap()
        .unwrap();
        let arcs: Vec<EdgeId> = mesh
            .edges
            .iter()
            .filter(|(_, e)| e.is_active() && matches!(e.curve(), Some(AnalyticCurve::Arc { .. })))
            .map(|(id, _)| id)
            .collect();
        let lines: Vec<EdgeId> = mesh
            .edges
            .iter()
            .filter(|(_, e)| {
                e.is_active()
                    && !matches!(
                        e.curve(),
                        Some(AnalyticCurve::Arc { .. }) | Some(AnalyticCurve::Circle { .. })
                    )
            })
            .map(|(id, _)| id)
            .collect();
        assert!(arcs.len() >= 4, "≥4 rim arcs (the 4 정점 case), got {}", arcs.len());

        // ── (1) FIX — trim assigns ONE shared owner to every rim arc ──
        let owner = mesh
            .edge_curve_owner_id(arcs[0])
            .expect("FIX: trim assigns a curve_owner_id to rim arcs (was None → facet 픽)");
        for &a in &arcs {
            assert_eq!(
                mesh.edge_curve_owner_id(a),
                Some(owner),
                "FIX: all rim arcs share ONE owner (1 logical circle, not fragmented)"
            );
        }

        // ── (2) ADR-088 grouping — edges_by_curve_owner returns the WHOLE rim ──
        let group = mesh.edges_by_curve_owner(owner);
        assert_eq!(
            group.len(),
            arcs.len(),
            "shared owner groups all {} rim arcs into 1 logical circle (got {})",
            arcs.len(),
            group.len()
        );
        for &a in &arcs {
            assert!(group.contains(&a), "every rim arc in the owner group");
        }
        // 사용자 규칙 — Line/Circle 독립: the chord (Line) must NOT carry the rim owner.
        for &l in &lines {
            assert_ne!(
                mesh.edge_curve_owner_id(l),
                Some(owner),
                "chord (Line) independent of the rim curve owner"
            );
        }

        // ── (3) split_arc_edge_at PROPAGATES owner to both children ──
        // Re-splitting an owned rim arc must keep both children in the same owner
        // group so the rim stays 1 logical curve after further cuts (2nd fix site).
        let arc0 = arcs[0];
        let (sa, ea) = match mesh.edges[arc0].curve() {
            Some(AnalyticCurve::Arc { start_angle, end_angle, .. }) => (*start_angle, *end_angle),
            _ => panic!("arc"),
        };
        let bv = DVec3::Z.cross(DVec3::X);
        let amid = (sa + ea) * 0.5;
        let pmid = center + radius * (DVec3::X * amid.cos() + bv * amid.sin());
        let (_v, c1, c2) = mesh.split_arc_edge_at(arc0, pmid).unwrap();
        // FIX: both children inherit the parent arc's owner → rim grouping survives.
        assert_eq!(
            mesh.edge_curve_owner_id(c1),
            Some(owner),
            "FIX: split_arc_edge_at propagates owner to child 1"
        );
        assert_eq!(
            mesh.edge_curve_owner_id(c2),
            Some(owner),
            "FIX: split_arc_edge_at propagates owner to child 2"
        );
    }

    /// **사용자 버그 isolation (2026-06-15)** — 얇은 bar 가 작은 원을 관통
    /// (2 평행 선이 교차) 하면 한쪽 cap 의 arc 가 직선화되는 회귀. mesh-level
    /// 격리: line1 (단일 교차, split_circle_face_by_line) → arc 전체 보존 →
    /// line2 (관통, split_arc_faces_crossed_by_line) → arc 가 직선화되는가?
    /// 재현되면 mesh 버그 (split_face_by_chain / add_face_with_holes), 아니면
    /// scene 버그 (rederive). 전체 arc 각도합 (TAU 유지 = smooth).
    #[test]
    fn sim_thin_bar_penetration_arc_preservation() {
        use crate::curves::AnalyticCurve;
        use std::f64::consts::TAU;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let center = DVec3::ZERO;
        let r = 50.0;
        let anchor = mesh.add_vertex(center + DVec3::X * r);
        let circle = AnalyticCurve::Circle { center, radius: r, normal: DVec3::Z, basis_u: DVec3::X };
        let fid = mesh.add_face_closed_curve(anchor, circle, mat).unwrap();

        let dir = DVec3::new(40f64.to_radians().cos(), 40f64.to_radians().sin(), 0.0);
        let perp = DVec3::new(-dir.y, dir.x, 0.0);

        // total angular coverage of r=50 arcs (TAU = whole rim still curved).
        let arc_coverage = |m: &Mesh| -> f64 {
            let mut total = 0.0;
            for (_, e) in m.edges.iter() {
                if !e.is_active() { continue; }
                if let Some(AnalyticCurve::Arc { radius, start_angle, end_angle, .. }) = e.curve() {
                    if (radius - r).abs() < 1e-6 {
                        total += (end_angle - start_angle).abs();
                    }
                }
            }
            total
        };

        // line1 (offset +15) — single edge split → arcs cover the full circle.
        let l1c = perp * 15.0;
        mesh.split_circle_face_by_line(fid, l1c - dir * 100.0, l1c + dir * 100.0, mat)
            .unwrap()
            .unwrap();
        let cov1 = arc_coverage(&mesh);
        assert!(
            (cov1 - TAU).abs() < 0.05,
            "after line1 (single edge), arcs cover full circle: got {:.4} (TAU={:.4})",
            cov1, TAU
        );

        // line2 (offset -15) — penetrating second edge → split the OTHER cap.
        let l2c = perp * -15.0;
        mesh.split_arc_faces_crossed_by_line(l2c - dir * 100.0, l2c + dir * 100.0);
        let cov2 = arc_coverage(&mesh);
        // FIX target: penetration must NOT straighten — arcs still cover full rim.
        assert!(
            (cov2 - TAU).abs() < 0.05,
            "after line2 (penetration), arcs STILL cover full circle: got {:.4} (TAU={:.4}) \
             — drop = straightened cap (사용자 버그)",
            cov2, TAU
        );
    }

    /// **사용자 버그 isolation (2026-06-16)** — arc-bounded 면(원을 선으로 자른
    /// cap)을 Push/Pull(extrude) 하면 TOP cap 의 arc 경계가 직선화되어 facet 으로
    /// 렌더된다 (bottom 은 매끈). 원인: `push_pull_create_face` 가 top 을
    /// `add_face(&new_verts)` 로 생성 → 직선 edge (curve metadata 미전파).
    /// 본 시뮬: ① extrude 후 top 의 arc edge = 0 (버그) ② fix (각 bottom arc 를
    /// offset 만큼 translate 해 대응 top edge 에 부착) 후 top arc = bottom arc.
    #[test]
    fn sim_extrude_arc_cap_top_rim_arc_preservation() {
        use crate::curves::AnalyticCurve;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let r = 60.0;
        let anchor = mesh.add_vertex(DVec3::X * r);
        let circle = AnalyticCurve::Circle {
            center: DVec3::ZERO, radius: r, normal: DVec3::Z, basis_u: DVec3::X,
        };
        let fid = mesh.add_face_closed_curve(anchor, circle, mat).unwrap();
        // secant cut at y=25 → 2 arc caps (Plane surface inherited via split).
        let caps = mesh
            .split_circle_face_by_line(
                fid, DVec3::new(-90.0, 25.0, 0.0), DVec3::new(90.0, 25.0, 0.0), mat,
            )
            .unwrap()
            .unwrap();
        let cap = caps[0];

        // (count, total angular coverage) of Arc boundary edges of a face.
        let face_arc = |m: &Mesh, f: FaceId| -> (usize, f64) {
            let start = m.faces[f].outer().start;
            let hes = m.collect_loop_hes(start).unwrap_or_default();
            let (mut cnt, mut cov) = (0usize, 0.0f64);
            for he in hes {
                let eid = m.hes[he].edge();
                if let Some(AnalyticCurve::Arc { start_angle, end_angle, .. }) =
                    m.edges.get(eid).and_then(|e| e.curve())
                {
                    cnt += 1;
                    cov += (end_angle - start_angle).abs();
                }
            }
            (cnt, cov)
        };

        let (bot_arcs, bot_cov) = face_arc(&mesh, cap);
        assert!(bot_arcs >= 1, "arc cap has ≥1 Arc boundary edge, got {}", bot_arcs);

        // Extrude via push_pull — the production fallback path for a Mixed
        // (arc + chord) boundary face (create_solid rejects Mixed → push_pull).
        let dist = 70.0;
        let res = mesh.push_pull(cap, dist, mat).unwrap();
        let top = res.top_face;

        // ── FIX (push_pull_create_face §4c top rim curve preservation) is LIVE ──
        // The extruded top cap keeps the (translated) arcs automatically — each
        // bottom Arc edge propagates, translated by `offset`, to the matching top
        // edge. Before the fix, top had 0 Arc edges (straightened → facet render).
        let (top_arcs, top_cov) = face_arc(&mesh, top);
        assert_eq!(
            top_arcs, bot_arcs,
            "FIX: extruded top cap Arc count matches bottom ({} vs {})",
            top_arcs, bot_arcs
        );
        assert!(
            (top_cov - bot_cov).abs() < 1e-6,
            "FIX: top arc coverage = bottom (translated) — {:.4} vs {:.4}",
            top_cov, bot_cov
        );
        // NOTE: manifold validity is NOT asserted here — this isolated mesh sim
        // leaves the sibling cap (the OTHER half) sharing the chord edge, which
        // the real flow cleaves first (ADR-102 detach-on-arrangement). The
        // scene-level sim (full createSolidExtrude path) validates manifold.
    }

    /// **사용자 버그 회귀 (2026-06-16)** — ADR-102 cleave 의 curve↔edge alignment.
    /// `face_outer_edges` 순서가 `collect_loop_verts` 순서와 달라 cleave 가 곡선을
    /// 한 칸 밀려 재부착 → arc cap 의 한 호가 직선화 + chord 가 호로 회전 →
    /// extrude 시 flat facet. cleave 후 각 호가 호로, chord 가 직선으로 유지되어야.
    #[test]
    fn adr102_cleave_preserves_arc_edge_alignment() {
        use crate::curves::AnalyticCurve;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let r = 60.0;
        let anchor = mesh.add_vertex(DVec3::X * r);
        let circle = AnalyticCurve::Circle { center: DVec3::ZERO, radius: r, normal: DVec3::Z, basis_u: DVec3::X };
        let fid = mesh.add_face_closed_curve(anchor, circle, mat).unwrap();
        // secant → 2 arc caps (each: 2 arc edges + 1 straight chord).
        let caps = mesh
            .split_circle_face_by_line(fid, DVec3::new(-90.0, 20.0, 0.0), DVec3::new(90.0, 20.0, 0.0), mat)
            .unwrap()
            .unwrap();
        let cap = caps[0];

        // (#arc edges, #straight edges) of a face boundary.
        let arc_straight = |m: &Mesh, f: FaceId| -> (usize, usize) {
            let s = m.faces[f].outer().start;
            let verts = m.collect_loop_verts(s).unwrap_or_default();
            let n = verts.len();
            let (mut a, mut st) = (0, 0);
            for i in 0..n {
                let eid = m.find_edge(verts[i], verts[(i + 1) % n]);
                match eid.and_then(|e| m.edges.get(e)).and_then(|e| e.curve()) {
                    Some(AnalyticCurve::Arc { .. }) => a += 1,
                    _ => st += 1,
                }
            }
            (a, st)
        };
        let (a0, s0) = arc_straight(&mesh, cap);
        assert_eq!((a0, s0), (2, 1), "arc cap pre-cleave = 2 arcs + 1 chord");

        // ADR-102 cleave from the sibling cap (scene path does this before extrude).
        let sibs = mesh.collect_coplanar_siblings(cap).unwrap();
        assert_eq!(sibs.len(), 1, "the other cap is the coplanar sibling");
        let new_cap = mesh.cleave_face_from_siblings(cap, &sibs).unwrap().new_face_id;

        // FIX — cleave must preserve the alignment: still 2 arcs + 1 chord (NOT
        // a rotated 1 arc + 2 chord that straightens an arc → facet).
        let (a1, s1) = arc_straight(&mesh, new_cap);
        assert_eq!(
            (a1, s1), (2, 1),
            "FIX: cleave preserves curve↔edge alignment (2 arcs + 1 chord), got ({}, {})",
            a1, s1
        );
    }

    /// **CAD trim item 3 (2026-06-15)** — `split_arc_face_by_line` cuts an
    /// arc-bounded face (lens half-disk analogue) with a line, splitting the
    /// crossed rim **arcs** at the interior crossings (arc-aware) and the face by
    /// the chord. Rim stays smooth (arcs preserved, NOT straightened) — the
    /// general "선×arc 면" case behind the rect-over-lens pin-down.
    #[test]
    fn cad_trim_split_arc_face_by_line() {
        use crate::curves::AnalyticCurve;
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let center = DVec3::ZERO;
        let radius = 100.0;
        let anchor = mesh.add_vertex(center + DVec3::X * radius);
        let circle = AnalyticCurve::Circle { center, radius, normal: DVec3::Z, basis_u: DVec3::X };
        let fid = mesh.add_face_closed_curve(anchor, circle, mat).unwrap();
        // trim at top/bottom → arc-bounded disk (4 arc segments, NO chord).
        let (arc_face, _) = mesh
            .trim_circle_face_at_crossings(
                fid,
                &[DVec3::new(0.0, radius, 0.0), DVec3::new(0.0, -radius, 0.0)],
                mat,
            )
            .unwrap()
            .unwrap();
        assert_eq!(mesh.faces.iter().filter(|(_, f)| f.is_active()).count(), 1);
        let arcs_before = mesh
            .edges
            .iter()
            .filter(|(_, e)| e.is_active() && matches!(e.curve(), Some(AnalyticCurve::Arc { .. })))
            .count();

        // horizontal cutter at y=50 → crosses 2 rim arc interiors (x=±86.6).
        let faces = mesh
            .split_arc_face_by_line(
                arc_face,
                DVec3::new(-150.0, 50.0, 0.0),
                DVec3::new(150.0, 50.0, 0.0),
                mat,
            )
            .unwrap()
            .expect("arc face split Some");
        assert_eq!(faces.len(), 2, "line splits arc face into 2, got {}", faces.len());
        assert_eq!(mesh.faces.iter().filter(|(_, f)| f.is_active()).count(), 2);

        // rim stays arc (the 2 crossed arcs split into 4 → MORE arcs, not fewer).
        let arcs_after = mesh
            .edges
            .iter()
            .filter(|(_, e)| e.is_active() && matches!(e.curve(), Some(AnalyticCurve::Arc { .. })))
            .count();
        assert!(
            arcs_after > arcs_before,
            "crossed rim arcs split (arc-aware), {} → {}",
            arcs_before,
            arcs_after
        );
        // every active arc edge stays ON the circle (rim not straightened).
        for (_, e) in mesh.edges.iter() {
            if let Some(AnalyticCurve::Arc { center: c, radius: r, normal: n, basis_u: u, start_angle, end_angle }) = e.curve() {
                if !e.is_active() {
                    continue;
                }
                let bv = n.cross(*u).normalize_or_zero();
                let amid = (start_angle + end_angle) * 0.5;
                let pmid = *c + *r * (*u * amid.cos() + bv * amid.sin());
                assert!(((pmid - *c).length() - *r).abs() < 1e-3, "arc midpoint on rim");
            }
        }
        assert!(mesh.verify_face_invariants().is_valid(), "manifold valid after arc-face split");
    }

    #[test]
    fn adr097_t_gamma_recovery_progress_tracks_fixes_applied() {
        // Recovery 가 진행 안 되면 break (max iter 무한 루프 방지).
        // Single quad → BoundaryEdge only → 0 progress → PartialFailure
        // with fixes_applied=0.
        use crate::topology_damage::RecoveryOutcome;
        let mut mesh = Mesh::new();
        let _ = build_quad_face(&mut mesh);
        let outcome = mesh.attempt_auto_recovery();
        match outcome {
            RecoveryOutcome::PartialFailure { fixes_applied, .. } => {
                assert_eq!(fixes_applied, 0,
                    "no progress → break with 0 fixes");
            }
            other => panic!("expected PartialFailure, got {:?}", other.label()),
        }
    }

    #[test]
    fn adr097_t_beta_inactive_face_skipped() {
        // remove_face 후 inactive face 는 detect 에 포함 안 됨.
        let mut mesh = Mesh::new();
        let f = build_quad_face(&mut mesh);
        mesh.remove_face(f).expect("remove OK");
        let report = mesh.detect_topology_damage();
        // face 는 inactive — checked_faces 0
        assert_eq!(report.checked_faces, 0,
            "inactive face must be skipped");
    }

    // ════════════════════════════════════════════════════════════════
    // ADR-101 Phase A — polygonize_closed_curve_face regressions
    // ════════════════════════════════════════════════════════════════

    /// Build a Path B Circle face at the given center / radius.
    fn build_circle_face(
        mesh: &mut Mesh,
        center: DVec3,
        radius: f64,
    ) -> FaceId {
        let mat = MaterialId::new(0);
        let anchor = mesh.add_vertex(center);
        let circle = crate::curves::AnalyticCurve::Circle {
            center,
            radius,
            normal: DVec3::Z,
            basis_u: DVec3::X,
        };
        mesh.add_face_closed_curve(anchor, circle, mat)
            .expect("Circle face creation")
    }

    #[test]
    fn adr101_phase_a_polygonize_circle_face_happy_path() {
        // Circle r=5 → polygonize → Some(new_fid). The new face must be
        // a polygonal N-vert face with N >= 8 (chord_tol radius/100
        // floor enforced by segment_count_for_arc).
        let mut mesh = Mesh::new();
        let circle = build_circle_face(&mut mesh, DVec3::ZERO, 5.0);
        let mat = MaterialId::new(0);

        let result = mesh.polygonize_closed_curve_face(circle, mat)
            .expect("polygonize must not error on valid Circle face");
        let new_fid = result.expect("Circle must polygonize → Some(new_fid)");

        // Original face is removed (inactive).
        assert!(
            !mesh.faces.get(circle)
                .map(|f| f.is_active())
                .unwrap_or(false),
            "original closed-curve face must be inactive after polygonize",
        );

        // New face is active and polygonal (N >= 8 boundary verts).
        let new_face = mesh.faces.get(new_fid)
            .expect("new face must exist");
        assert!(new_face.is_active(), "new polygon face must be active");
        let new_loop = mesh.collect_loop_verts(new_face.outer().start)
            .expect("new face must have a valid outer loop");
        assert!(
            new_loop.len() >= 8,
            "polygonized circle must have >= 8 chord segments (got {})",
            new_loop.len(),
        );
    }

    #[test]
    fn adr101_phase_a_polygonize_noop_for_polygonal_face() {
        // Rect (4-vert polygon) → returns Ok(None), unchanged.
        let mut mesh = Mesh::new();
        let rect = build_quad_face(&mut mesh);
        let mat = MaterialId::new(0);
        let before_active = mesh.faces[rect].is_active();

        let result = mesh.polygonize_closed_curve_face(rect, mat)
            .expect("polygonize must not error on polygonal face");
        assert!(
            result.is_none(),
            "polygonal face must return None (was Some({:?}))",
            result,
        );
        assert_eq!(
            mesh.faces[rect].is_active(),
            before_active,
            "polygonal face must be untouched (still active)",
        );
    }

    #[test]
    fn adr101_phase_a_polygonize_noop_for_non_circle_self_loop() {
        // Closed Bezier face → Ok(None). The Bezier face must remain
        // intact; ADR-101 Phase A only handles Circle.
        let mut mesh = Mesh::new();
        let mat = MaterialId::new(0);
        let anchor = mesh.add_vertex(DVec3::ZERO);
        // Trivial closed Bezier — 3 control points forming a triangle
        // with cp[0] == cp[last] (closure requirement).
        let bez = crate::curves::AnalyticCurve::Bezier {
            control_pts: vec![
                DVec3::new(0.0, 0.0, 0.0),
                DVec3::new(1.0, 0.0, 0.0),
                DVec3::new(0.5, 1.0, 0.0),
                DVec3::new(0.0, 0.0, 0.0),
            ],
        };
        let bezier_face = mesh.add_face_closed_curve(anchor, bez, mat)
            .expect("Bezier closed face creation");
        let before_active = mesh.faces[bezier_face].is_active();

        let result = mesh.polygonize_closed_curve_face(bezier_face, mat)
            .expect("polygonize must not error on Bezier face");
        assert!(
            result.is_none(),
            "Bezier closed curve must return None (deferred — Phase A is Circle-only)",
        );
        assert_eq!(
            mesh.faces[bezier_face].is_active(),
            before_active,
            "Bezier face must be untouched",
        );
    }

    #[test]
    fn adr101_phase_a_polygonize_surface_inheritance() {
        // Circle with Plane surface attached → new polygon inherits
        // the same Plane variant.
        let mut mesh = Mesh::new();
        let circle = build_circle_face(&mut mesh, DVec3::ZERO, 3.0);
        let plane = crate::surfaces::AnalyticSurface::Plane {
            origin: DVec3::ZERO,
            normal: DVec3::Z,
            basis_u: DVec3::X,
            u_range: (-1e6, 1e6),
            v_range: (-1e6, 1e6),
        };
        mesh.faces.get_mut(circle)
            .expect("circle face exists")
            .set_surface(Some(plane));

        let mat = MaterialId::new(0);
        let new_fid = mesh.polygonize_closed_curve_face(circle, mat)
            .expect("polygonize OK")
            .expect("Circle must polygonize");

        let new_face = mesh.faces.get(new_fid)
            .expect("new face exists");
        assert!(
            matches!(
                new_face.surface(),
                Some(crate::surfaces::AnalyticSurface::Plane { .. }),
            ),
            "Plane surface must be inherited onto the polygonized face",
        );
    }

    #[test]
    fn adr101_phase_a_polygonize_anchor_deactivated_if_isolated() {
        // The Circle's anchor vertex has no other edges → must be
        // deactivated after polygonization so it doesn't render as a
        // stray dot at the center.
        let mut mesh = Mesh::new();
        let circle = build_circle_face(&mut mesh, DVec3::ZERO, 2.0);
        let mat = MaterialId::new(0);

        // Pre-polygonize: locate the anchor (the single boundary vert).
        let anchor = {
            let face = mesh.faces.get(circle).unwrap();
            let loop_verts = mesh.collect_loop_verts(face.outer().start)
                .unwrap();
            assert_eq!(
                loop_verts.len(), 1,
                "Path B Circle has a 1-vert boundary loop",
            );
            loop_verts[0]
        };

        let _ = mesh.polygonize_closed_curve_face(circle, mat)
            .expect("polygonize OK")
            .expect("must polygonize");

        // Anchor should be inactive — it has no other outgoing edges.
        assert!(
            !mesh.verts[anchor].is_active(),
            "isolated anchor must be deactivated post-polygonize",
        );
    }

    #[test]
    fn adr101_phase_a_polygonize_invariants_preserved() {
        // After polygonize the mesh must pass face invariants — no
        // degenerate normals, no orphan HEs, no non-manifold edges
        // introduced by the rewrite.
        let mut mesh = Mesh::new();
        let circle = build_circle_face(&mut mesh, DVec3::ZERO, 4.0);
        let mat = MaterialId::new(0);
        let _ = mesh.polygonize_closed_curve_face(circle, mat)
            .expect("polygonize OK")
            .expect("must polygonize");

        let report = mesh.verify_face_invariants();
        assert!(
            report.is_valid(),
            "post-polygonize mesh must satisfy face invariants — got {:?}",
            report.violations,
        );
    }

    #[test]
    fn adr101_phase_a_polygonize_inactive_face_errors() {
        // Passing an inactive face_id must error — not silent no-op,
        // because that hides programming errors at the caller.
        let mut mesh = Mesh::new();
        let circle = build_circle_face(&mut mesh, DVec3::ZERO, 2.0);
        mesh.remove_face(circle).expect("manual remove for test");
        let mat = MaterialId::new(0);

        let result = mesh.polygonize_closed_curve_face(circle, mat);
        assert!(
            result.is_err(),
            "polygonize on inactive face must error, got {:?}",
            result,
        );
    }

